-- Table structure for `buildings_en`
DROP TABLE IF EXISTS `buildings_en`;
CREATE TABLE `buildings_en` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `buildingName` varchar(255) NOT NULL,
  `buildingAuthor` varchar(255) DEFAULT NULL,
  `buildingAddress` varchar(255) DEFAULT NULL,
  `buildingDescription` text DEFAULT NULL,
  `imageSrc` varchar(500) DEFAULT NULL,
  `latitude` decimal(10,8) DEFAULT NULL,
  `longitude` decimal(11,8) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=MyISAM AUTO_INCREMENT=47 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

