INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('1', 'Kauno centrinio pašto rūmai (dabar – Nacionalinis architektūros institutas)', '1930 m., architektas Feliksas Vizbaras', 'Laisvės al. 102', '<p class=\"ql-align-justify\">1929 m. nuspręsta statyti naują Centrinį paštą – modernios ryšių sistemos epicentrą ir simbolį. Tais pačiais metais Lietuvos susisiekimo ministerija paskelbė rūmų projekto konkursą, kurį laimėjo architektas F. Vizbaras. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Planas pristatytas kaip novatoriška lietuvių liaudies architektūros interpretacija, atkartojanti tipišką lietuviško kaimo kotedžo išplanavimą, tradicinio audimo raštus frize ir dekoratyvinėse grindų dangose, modernaus tautinio stiliaus paieškas sandorių salėje.</p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Per mažiau kaip vienerius metus iškilo 5 aukštų pastatas su drąsiu simetrišku fasadu ir plokščiu stogu.  Rūmai tapo vienu svarbiausių architektūrinių laikinosios sostinės akcentų. Čia darbus išskirtinai vykdė tik vietiniai darbininkai, rūmų interjerą papuošė žymiausių to meto dailininkų kūriniai: operacijų salės viršų puošė Vilniaus, Gardino ir Klaipėdos herbai bei trys dailininko Kazio Šimonio paveikslai. Aplink visą salę išsirikiavo 103 dailininkų Petro ir Rimto Kalpokų nutapyti Lietuvos pašto ženklai. </p><p class=\"ql-align-justify\"><br></p><p class=\"ql-align-justify\">Okupavus Lietuvą, sovietai siekė sumažinti pastato simbolinę reikšmę: užtinkuotos atminimo lentos su rėmėjų ir projekto steigėjų pavardėmis, nuo fasado nuimtas atminimo medalionas. Atkūrus Lietuvos nepriklausomybę, stengtasi restauruoti interjero detales. 2024 m. čia savo veiklą pradėjo vykdyti Nacionalinis architektūros institutas.</p><p><br></p>', 'https://modernist.kaunas.lt/ehl-pastatai/1.jpg', '54.89814140', '23.90447380');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('2', 'Vytauto Didžiojo karo ir Nacionalinis M. K. Čiurlionio dailės muziejai', '1921–1936 m., architektai Vladimiras Dubeneckis, Karolis Reisonas', 'K. Donelaičio g. 64 / V. Putvinskio g. 55', '<p>Nacionalinio muziejaus idėja kilo XX a. pradžioje, pastūmėta nacionalizmo bangos. Vėliau suvokta, kad tai turėtų būti ne tik valstybingumo paminklas, kolektyvinės tautinės atminties artefaktų saugykla, bet ir modernios visuomenės ugdymo bei raidos institucija. </p><p><br></p><p>Kompleksas pradėtas formuoti 1921 m., sename mediniame manieže įrengus Lietuvos nepriklausomybės kovų ekspoziciją, pastačius pirmąjį muziejaus sodelio paminklą –  „Žuvusiems už Lietuvos laisvę“. Akmenys jam surinkti ir atvežti iš Nepriklausomybės kovų vietų, vėliau – 1934-aisiais – čia iškilmingai palaidotas ir Nežinomas kareivis. </p><p><br></p><p>1929 ir 1930 m. surengti du konkursai, įpareigojant viename pastate įkurti muziejus: karo istorijos ir kultūros. Laimėtojai – garsiausi tarpukario Lietuvos architektai V. Dubeneckis ir K. Reisonas. 1930 m. pašventinti pastato kertiniai akmenys, suteiktas Vytauto Didžiojo vardas. Monumentalaus pastato kompozicija siekta simetrijos, tačiau fasadai – skirtingi. </p><p><br></p><p>Karo muziejaus arkados išplečia pagrindinį pastatą, sujungia jį su varpine, kurios dekoras temiškai susietas su muziejaus salėmis, ten esančiais paminklais. Kultūros muziejaus fasadas dinamiškesnis. Pagrindinis akcentas –  paralelė į karūnos atvaizdą M. K. Čiurlionio paveiksluose: pusapvalė centrinė fasado dalis su vertikaliais siaurais langais ir tarpiniais piliastrais, dengtais variniais stogeliais.</p><p><br></p><p>Muziejaus interjeras taip pat būdingas iškilmingiems visuomeniniams pastatams: vyrauja baltos, pilkos, juodos ir tamsios medienos spalvos, kuriamas iškilmingas ir diskretiškas fonas eksponatams.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/2.jpg', '54.89988250', '23.91186280');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('3', 'Lietuvos karininkų ramovės reprezentaciniai rūmai', '1931–1937 m., architektas Stasys Kudokas', 'A. Mickevičiaus g. 19', '<p>Karinė jėga laikyta vienu iš pagrindinių tarpukario Lietuvos valstybės suvereniteto garantų, o karininkai siekė stiprinti šią nuomonę bei gyventojų pasitikėjimą aktyviai dalyvaudami šalies politiniame, visuomeniniame ir kultūriniame gyvenime. Taip pasiryžta sukurti simbolinę erdvę, leisiančią patirti Lietuvos istorijos didybę.</p><p><br></p><p>1931 m. vykusiame tarptautiniame konkurse sulaukta apie trisdešimt architektų ir komandų pasiūlymų. Laimėtojais tapo estai E. Lohkas ir H. Voldemaras Johansonas, tačiau projektą įgyvendino lietuvių architektai. 1937 m. balandžio 23 d. atidaryta Karininkų ramovė iškart tapo vienu iš prabangiausių tarpukario Kauno pastatų ir centrine miesto visuomeninio gyvenimo dalimi: karininkų susitikimų, oficialių valstybinių švenčių, priėmimų, konferencijų vieta. </p><p><br></p><p>Pastatui būdingas klasikos ir modernizmo derinys: pirmąjį aukštą puošia granito kolonos ir puskolonės, fasadą užbaigia platus karnizas ir stogą slepiantis atikas, išryškinti antrojo aukšto (it. piano nobile) langai. Istorinės patalpos kontrastuoja su modernia plieninio karkaso įstiklinta oranžerija. </p><p><br></p><p>Lietuvos teritorinį integralumą virš centrinio įėjimo simbolizuoja Broniaus Pundziaus granito reljefai su Vilniaus, Kauno ir Klaipėdos herbais bei nuo karnizo žvelgianti  „Trys milžinai“ skulptūra.</p><p><br></p><p>Pastatas turi rūmams būdingą trijų dalių struktūrą: visuomeninis pirmas aukštas su vestibuliais ir rūbinėmis, restoranu bei simetriškai išdėstytais laiptais, vedančiais į reprezentacinį aukštą su teminėmis salėmis (Vytauto Didžiojo sale, Prezidento kambariu bei Kunigaikščių mene) ir laisvalaikio erdvėmis, o  viršuje – „gyvenamasis“ aukštas su atvirais balkonais-lodžijomis bei viešbučiu laikinam apsistojimui.</p>', '../../ehl-pastatai69e87713b6092.jpg', '54.89666570', '23.91645900');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('4', 'Valstybinės taupomosios kasos (dabar – Kauno miesto savivaldybės administracija)', '1938–1940 m., architektai Arnas Funkas, Adolfas Lukošatis, Bronius Elsbergas', 'Laisvės al. 96', '<p>Vienas paskutiniųjų tarpukariu pastatytų visuomeninių pastatų – Valstybės taupomoji kasa. Objektas turėjo būti projektuojamas puošnus, jame diegiamos naujausios technologijos. Specialiai sudaryta komisija net apžiūrinėjo panašius pastatus Europos šalyse. </p><p><br></p><p>Tarptautinis pastato projektavimo konkursas paskelbtas 1938 m. Jis sulaukė apie septyniasdešimt septynių pasiūlymų, galutinis dizainas sukurtas iš trijų žiuri atrinktų projektų.</p><p><br></p><p>Gyventojai šešių aukštų pastatą pavadino „Kauno dangorėžiu“, kuriame greta taupomųjų kasų turėjo sutilpti Prekybos departamentas, Statistikos biuras ir įvairios kitos valstybinės įstaigos. Darbuotojų patogumui įrengti net du liftai nieko nebestebino, tačiau pneumatinis paštas tapo moderniu įstaigos atributu, pagreitinusiu korespondencijos „keliones“ tarp aukštų. Rūsyje patalpintas gyventojų santaupas saugojęs seifas. </p><p><br></p><p>Pastatą sudaro trys 6 ir 5 aukštų korpusai, suformuojantys pusiau uždarą kiemą. Statinys pasižymi griežtomis geometrinėmis formomis, lakoniška planine ir kompozicine struktūra. Ties pagrindine rūmų įeiga įrengtos sukamos durys. </p><p>Pirmas aukštas papuoštas poliruoto tašyto granito plokštėmis, o aukščiau – pilko granito tinku. Pastato konstrukcija remiasi į metalinį karkasą, o stogai plokšti, išskyrus pagrindinės salės stogą, kuriame sukurtos unikalios Art Deco stiliaus lubos: juodo metalo rėmas kuria geometrinį raštą. </p><p><br></p><p>Apdailoje subtiliai panaudoti tautiniai motyvai: tulpės, rūtelės, saulutės, rodyklės ir kiti modernistiniai bei tautiniai motyvai. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/4.jpg', '54.89827810', '23.90645950');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('5', 'Kauno apskrities savivaldybės rūmai (dabar – Kauno apskrities policijos komisariatas)', '1933 m., architektas Vytautas Landsbergis-Žemkalnis', 'Vytauto pr. 91', '<p>Modernus pastatas formavo naujosios sostinės veidą: 1933-aisiais iškilę rūmai po vienu stogu sutalpino dvi institucijas: į Laisvės alėją nukreiptą sparną užėmė Kauno apskrities savivaldybės įstaigos ir policijos komisariatas, o Vytauto prospekto sparnas priskirtas Valstybės saugumo departamentui ir kriminalinei policijai, rūsyje įrengtos kameros. </p><p><br></p><p>Kieme pastatytas 2 aukštų garažas su butais vairuotojams ir spaustuve. Statybų techninę priežiūrą vykdė inžinieriai Algirdas Šalkauskas ir Borisas Helcermanas.</p><p><br></p><p>Geometriškai griežta architektūra, siauri langai ir skiriamieji piliastrai turėjo reprezentatyvumo įspūdį, būdingą kitiems tarpukario Kauno visuomeniniams pastatams. Pastatas aplinkiniame kontekste išsiskyrė ne tik modernistinėmis geometrinėmis formomis, bet ir prabanga. Vidaus apdaila ir inžinerinės detalės pabrėžė gerai finansuojamų agentūrų statusą. Natūralaus tamsiai pilko granito akmens cokolis ir laiptai, juodo poliruoto labradorito portalai bei tamsaus dirbtinio granito piliastrai sudarė kontrastą su šviesaus granito fasadais. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/5.jpg', '54.89721990', '23.92493870');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('6', 'Prekybos, pramonės ir amatų rūmai (dabar – Kauno Ąžuolyno bibliotekos skyriai)', '1938 m., architektas Vytautas Landsbergis-Žemkalnis', 'K. Donelaičio g. 8', '<p>Lietuvos kūrėjai sutarė dėl vieno dalyko: ekonominė galia – gyvybiškai svarbus valstybingumo garantas. Vienu iš besiplečiančios šalies ekonomikos ir prekybos simbolių tapo Prekybos ir pramonės rūmai – 1925 metais įkurta institucija, koordinuojanti ir atstovaujanti gamintojų bei prekybininkų interesus. Simbolinė jo svarba buvo priminti piliečiams, kad stipri ekonomika – šalies klestėjimo pagrindas. </p><p><br></p><p>1931 m. nuspręsta pastatyti modernius reprezentacinius rūmus-būstinę. Sulaukta didelio susidomėjimo – pateikti net 29 projektai, pastatą sukurti patikėta architektui Vytautui Landsbergiui-Žemkalniui, pasiūliusiam vadovautis klasikine tradicija, tautiniu stiliumi. Tai turėjo reprezentuoti šalies teritorinį vientisumą, jos demografinius išteklius, socialinę sanglaudą, nacionalines vertybes ir nuolatinį pramonės, prekybos, žemės ūkio bei amatų sektorių augimą. </p><p><br></p><p>Iš pradžių rūmams numatyta vieta greta Karo muziejaus varpinės, tačiau nuspręsta toliau formuoti svarbią Naujamiesčio arteriją – K. Donelaičio gatvę. Tam nupirkti du sklypai. </p><p><br></p><p>Pastate atsiskleidžia lietuviškajai architektūrai būdingas santūrumas, solidumas, architektūros ir taikomojo meno sintezė. Trijų aukštų rūmų pagrindinis korpusas pastatytas išilgai K. Donelaičio g., fasadą vertikaliai skaido lizenos ir arkinė įėjimo anga. Šoninis fasadas neutralus – jį horizontaliai dalija trys ilgos langų juostos. </p><p><br></p><p>Įėjimai akcentuoti embleminiais reljefais „Pramonė“ ir „Prekyba“. Penkios P. Kalpoko sienų tapybos kompozicijos papuošė vestibiulį, Stasio Ušinsko vitražai „Lietuvaitis“ ir „Lietuvaitė“ – laiptinę. Dar vienas simbolinis akcentas: B. Pundziaus metalinės vazos, dekoruotos reljefiniais fabrikų vaizdais.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/6.jpg', '54.89835870', '23.92491800');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('7', 'Žaliakalnio funikulierius', '1931 m., projektą parengė „Curt Rudolph Transportanlagen“, naujus 1937 m. suprojektavo inžinierius Napoleonas Daukas-Dobkevičius', 'Aušros g. 6', '<p>Tarpukariu miesto modernumas buvo siejamas su infrastruktūros gerinimu. Istoriniai funikulieriai – vienas ryškiausių ženklų, liudijančių Kauno augimą. Siekiant skatinti ir paspartinti Žaliakalnio plėtrą, miesto valdžia 1927 m. pritarė funikulieriaus įrengimui.</p><p><br></p><p>Šios transporto priemonės statybas 1931 m. Žaliakalnyje inicijavo prezidentas Antanas Smetona ir miesto Burmistras Jonas Vileišis. Idėja kilo siekiant pagerinti susisiekimą tarp Naujamiesčio ir Žaliakalnio. Miestui plečiantis pastebėta, kad statybos aukštutinėje miesto dalyje sumažėjo, o apatinėje – padidėjo ir sklypų kainos čia smarkiai išaugo. Reiškinys buvo siejamas su tuo, kad patekimas iš vienos miesto dalies į kitą buvo sudėtingesnis.</p><p><br></p><p>Nusprendus statyti funikulierių, imta galvoti apie jam tinkamiausią vietą: imtasi netgi tam tikrų sociologinių tyrimų. Potencialiems būsimojo keltuvo srautams nustatyti, miesto savivaldybė pasamdė bedarbius, kurie stebėjo pirmyn ir atgal laiptais keliaujančius žmones.</p><p><br></p><p>Rezultatai atskleidė, kad daugiausia žmonių praeina Kauko g. (apie 4 000 į dieną), vidutiniškai Žemaičių g. (3 500) ir mažiausiai Aušros take (3 000). Taigi, buvo nutarta, kad keltuvas atsiras būtent čia – prie Putvinskio g. (tuo metu Kalnų g.) 22-uoju numeriu pažymėto namo ir kils iki pat Aušros ir Žemaičių gatvių sankirtos.</p><p><br></p><p>Naujoje transporto priemonėje iš pradžių buvo įrengtas tik vienas vagonas, o antrasis prikrautas akmenų ir naudojamas kaip atsvara. Funikulieriui smarkiai populiarėjant netrukus buvo atidarytas ir antras keleivinis vagonas. Taip pat apatinėje stotelėje įrengta užuovėja, o vėliau – ir stoginė, kuri nepakitusi iki šių dienų.</p><p><br></p><p>Funikulierius buvo naudojamas ne tik su tikslu pasiekti būtiniausias įstaigas, bet tapo ir miesto lankytojų traukos objektu. Skaičiuojama, kad tarpukariu Žaliakalnio funikulierius per darbo dieną kildavo ir leisdavosi virš 200 kartų bei vidutiniškai perveždavo per 3 tūkst. keleivių, kurių vienu metu vagone galėdavo tilpti 35. Bėgiai tęsėsi 142 metrus, o kelionė truko 1 min. 38 sek.</p><p><br></p><p>Funikulierių suprojektavo ir pagamino Leipcige įsikūrusi inžinerijos įmonė „Curt Rudolph Transportanlagen“, o elektros įrangą tiekė korporacija  „AEG“. Lietuvos ir Amerikos prekybos įmonė „Amlit“ funikulieriaus bėgių vagonus gamino Kaune. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/7.jpg', '54.90199690', '23.91789750');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('8', '„Pažangos“ bendrovės rūmai', '1934 m., architektas Feliksas Vizbaras', 'Laisvės al. 53', '<p>1928 m. įkurta bendrovė „Pažanga“ priklausė valdančiajai Tautininkų partijai, anksčiau vadinamai  Nacionaline pažangos partija.  Būtent taip ir kilo korporacijos, o vėliau ir rūmų  pavadinimas.</p><p><br></p><p>1933–1934 m. statytame dideliame penkių aukštų pastate veikė partijos būstinė, „Lietuvos aido“ ir „Jaunosios kartos“ redakcijos, Tautinė jaunimo sąjunga „Jaunoji Lietuva“. Antrame aukšte įsikūrė Nacionalinis klubas su užkandžių baru ir restoranu. Lankytojai galėdavo liftu pakilti į plokščio stogo terasą. </p><p><br></p><p>Pirmame aukšte veikė „Paramos“ bendrovės galanterijos prekių parduotuvė, „Dirvos“ bendrovės knygynas. 1934 m. čia persikėlė Valstybės centrinis knygynas ir biblioteka. Giliame rūsyje, besitęsiančiame po visu kiemu, buvo posėdžių salės bei skaitykla apšviečiamos švieslangiais iš stiklo blokelių. </p><p><br></p><p>Ieškodamas modernaus tautinio stiliaus, architektas F. Vizbaras fasade ir interjeruose naudojo Art Deco motyvus: geometrijas, zigzagus, augalijos elementus.</p><p><br></p><p>Abiejuose pirmo aukšto šonuose buvo įėjimai – vakarinis vedė į reprezentacinę zoną, rytinis – į kiemo korpusus. Virš „Lietuvos aido“ redakcijos kurį laiką gyveno Ministras Pirmininkas Juozas Tūbelis, o 1935 m. į butą „Pažangos“ rūmuose įsikėlė politikas, taip pat buvęs Ministras Pirmininkas, vienas bendrovės „Pažanga“ steigėjų, Nepriklausomybės Akto signataras, kun. Vladas Mironas. Po 1940-ųjų rūmuose buvo įvairių mokslinių tyrimų įstaigų, kiemo korpusuose – butai, Laisvės al. – parduotuvė.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/8.jpg', '54.89709910', '23.91421650');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('9', 'Vytauto Didžiojo universiteto Medicinos fakulteto rūmai', '1933 m., architektas Vladimiras Dubeneckis', 'A. Mickevičiaus g. 9', '<p>Kauno Medicinos fakulteto rūmai – XX a. pirmosios pusės neoklasicizmo architektūros pavyzdys, atspindintis pereinamąją fazę tarp retrospektyvizmo ir modernizmo. Simetriškas ir monumentalus pastatas balansuoja tarp modernumo ir klasikinės tradicijos.</p><p> </p><p>Pastatas suprojektuotas 1930 m., remiantis Briuselio universiteto Medicinos fakulteto projektu, prisitaikant prie ekonominių Lietuvos galimybių – kuklesnis ir paprastesnis, orientuotas į praktiškumą. Kertinis akmuo pašventinti 1931 m. liepą, o rūmų statyba baigta greičiau nei per dvejus metus. </p><p><br></p><p>V. Dubeneckio statinys funkciškai suskirstytas į administracinius biurus ir mokymo patalpas, jungiamąjį sparną su klasių auditorijomis ir tyrimų korpusu. Šiuolaikiški rūmai priartino medicinos studentų ir profesorių darbo bei mokymosi sąlygas prie europinių standartų. </p><p><br></p><p>Iki tol spaudoje aptinkami makabriški pasakojimai: „kol fakultetas neturėjo įrengto anatomikumo, garsusis chirurgas ir anatomijos profesorius Jurgis Žilinskas lavonine buvo pavertęs savo butą“ („Lietuvos aidas“, 1931 m. liepos 4 d., Nr. 147), „sukalėme dvi medines skrynias lavonams laikyti, gavome suolų studentams“ (J. Žilinsko Atsiminimai. Vilnius: Lietuvos nacionalinis muziejus, 2005, p. 192.)</p><p><br></p><p>Rūmų fasaduose – simetrija, monumentalumas ir istoriniams objektams būdingi bruožai: ypatingai tuo pasižymi A. Mickevičiaus gatvės fasadas. Čia rizalitų supama centrinė dalis ir įėjimas, laiptuotas parapetas ir aukštas klasicistinis portalas primena istorinius rūmus. Spaustuvininkų gatvės fasadas gerokai modernesnis – lenktas ir gausiai įstiklintas.</p><p><br></p><p>Po vienu įstaigos stogu įsikūrė anatomijos, teismo ir socialinės medicinos bei bendrosios patologijos su patologine anatomija institutai, iki šiol veikiantis Anatomijos muziejus. A. Mickevičiaus gatvės korpuse – fiziologijos ir fiziologinės chemijos, farmakologijos, histologijos su embriologija ir farmacijos su farmakognozija patalpos. 1936 m. rūmų rūsyje įrengtas pirmasis Lietuvos krematoriumas.</p><p><br></p><p>Medicinos fakultetas turi reikšmingą vietą ir istoriniuose puslapiuose – 1933 metais tragiškai žuvę Lietuvos Atlanto nugalėtojai – Steponas Darius ir Stasys Girėnas – pripažinti tautos didvyriais, jų palaikus nutarta balzamuoti. Artėjant sovietų kariuomenei ir naujai rusų okupacijai, lakūnų palaikai paslėpti Medicinos fakulteto rūsyje iki pat 1963 m.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/9.jpg', '54.89430490', '23.91635660');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('10', 'Kauno Žemės banko pastatas (dabar – KTU centriniai rūmai)', '1935 m., architektas Karolis Reisonas', 'K. Donelaičio g. 73', '<p>1924 m. valstybės iniciatyva įkurta didžiausia žemės ūkį kredituojanti įstaiga – Žemės bankas, teikęs paskolas ūkininkams. Pastatas iškilo Vienybės aikštės pakraštyje, todėl architektas K. Reisonas siekė, kad bankas neužgožtų muziejaus.</p><p><br></p><p>Keturių aukštų pastatas monumentalus: fasaduose matomas vertikalių ir horizontalių linijų ritmas,  prabangios apdailos medžiagos: granitinis tinkas, poliruoto granito danga ir meno kūriniai. Aukštas parapetas užstoja šlaitinį stogą, jį pagyvina stilizuotos rozetės, o ties rizalitais – skulptoriaus Bernardo Bučo sukurti bareljefai, vaizduojantys valstiečių galvas. Statybai panaudotas itin didelis kiekis gelžbetonio. Pagrindinis rūmų akcentas – kampinis centrinis įėjimas su plačiais granitiniais laiptais. </p><p><br></p><p>Rūmus sudaro 3 skirtingo dydžio korpusai, kuriuose sutilpo bankinių operacijų salės, kasos, seifo kambarys. Pastate taip pat įsikūrė Užsienio reikalų ministerijos biurai, į kuriuos galima patekti atskiru įėjimu ir liftu. Čia dirbo paskutinieji nepriklausomos Lietuvos užsienio reikalų ministrai: S. Lozoraitis (1934–1938 m.) ir J. Urbšys (1938–1940 m.).</p><p><br></p><p>1935 m. vis labiau įsigalint funkcionalizmui, interjere prioritetas skirtas erdvioms, šviesioms ir higieniškoms patalpoms: „brangių įrengimų, visokių gipso pagražinimų ir ornamentų, nors ir puošiančių vidaus įrengimą, tačiau visuomet padedančių dulkėms laikytis, naujai pastatytuose Žemės banko namuose nėra“ („Lietuvos aidas“, 1935, vasario 12).</p>', 'https://modernist.kaunas.lt/ehl-pastatai/10.jpg', '54.89880520', '23.91265260');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('11', '„Pienocentro“ bendrovės biuras', '1934 m., architektai Vytautas Landsbergis-Žemkalnis, Karolis Reisonas', 'Laisvės al. 55', '<p>1927 metais įkurta Lietuvos pieno perdirbėjų kooperatinė sąjunga „Pienocentras“. Ji tapo viena didžiausių Lietuvos pramonės įmonių, rūpinosi pieno produktų surinkimu, gamyba, pardavimu ir eksportu.</p><p><br></p><p>1931 metais „Pienocentro“ bendrovės administracinių rūmų projekto konkursą laimėjo architektas V. Landsbergis-Žemkalnis, prie projektavimo prisidėjo ir K. Reisonas. Konstrukcijų skaičiavimus atliko inžinieriai J. Milius ir P. Markūnas. Statybą, kuri tęsėsi iki 1934 m., organizavo rangovai L. Markovičius ir J. Kaplanas. </p><p><br></p><p>Pirmasis penkių aukštų pastatas Laisvės alėjoje lyginant su supančiais pastatais atrodė kaip dangoraižis. Tai bene įspūdingiausias daugiafunkcinio (komercinio bei gyvenamosios paskirties) pastato atitikmuo tarpukario Kaune.</p><p><br></p><p>Pirmame aukšte veikė „Pienocentro“ prekės ženklo gaminių parduotuvė ir pieno baras, greitai tapęs vienu pagrindinių miestelėnų traukos taškų. Greta atidaryta užkandinė, vadinta „Pienocentro“ darželiu. Dviejuose apatiniuose aukštuose įsikūrė garsioji kirpykla „Muralis Brothers“, kurios modernistinius interjerus sukūrė architektas Arnas Funkas. Trečiame aukšte įrengtos administracinės patalpos, o viršutiniuose aukštuose – butai. Kol Kaunas neturėjo centrinės pieninės, rūmų rūsyje buvo įrengta nedidelė pieninė ir šaldytuvas.</p><p><br></p><p>Pastatas neabejotinai gali būti laikomas vienu ryškiausių lietuviškojo funkcionalizmo pavyzdžiu: santūrus, simetriškas, papuoštas modernizuoto istorizmo statiniams būdingu profiliuotu karnizu. Lenktas pagrindinio fasado su vitrininiais langais, elektra apšviečiamas stogelis – primena europietišką ekspresionizmą. Modernumo ir elegancijos suteikė ir gaubti kampiniai langai, išlikę tik antrajame aukšte.</p><p><br></p><p>Kai šalia iškilo „Pažangos“ rūmai, jie tapo modernios europietiškos sostinės pagrindinio bulvaro užuomazgomis. Rūmai 1937 m. tarptautinėje parodoje „Exposition Internationale des Arts et des Techniques“ Paryžiuje apdovanoti garbės diplomu ir bronzos medaliu.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/11.jpg', '54.89709830', '23.91386320');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('13', 'Kūno kultūros akademijos rūmai (dabar – Lietuvos sporto universitetas)', '1934 m., architektas Vytautas Landsbergis-Žemkalnis', 'Sporto g. 6', '<p>Po Pirmojo pasaulinio karo nepriklausomybę atgavusioje Lietuvoje prioritetu laikyta žemdirbystė, o sportas vertintas kaip neturinčių ką veikti užsiėmimas. Viskas pasikeitė 1932 m., priėmus Kūno kultūros įstatymą. Sportas tapo nebe atskirų draugijų veikla, o valstybės populiarinama sritimi. Didžiulę įtaką tam padarė išeiviai iš Lietuvos, skleidę sporto ir sveikatingumo idėjas, mokę vietinius.</p><p><br></p><p>Vieni ryškiausių pavyzdžių – garsusis lakūnas Steponas Darius, kuris vos per septynerius mėnesius šalyje išpopuliarino net dešimt skirtingų sporto šakų ir inicijavo pirmojo stadiono Kaune statybas. Dar vienas žymus sporto pradininkas Lietuvoje – Steponas Garbačiauskas. Jo iniciatyva Vytauto parke įrengta pirmoji teniso aikštelė. Ir tai tik keli pavyzdžiai iš daugelio.</p><p><br></p><p>Pirmoji valstybinė sporto institucija savo veiklą pradėjo 1932 m. Kaune. Vis dėlto, pirmasis Kūno kultūros rūmų statybų etapas baigtas tik 1934 m. Iš pradžių svarstyta juos statyti Kęstučio gatvėje, bet vėliau vieningai nuspręsta, kad tam kur kas labiau tinka Ąžuolynas, esantis arti miesto centro, tačiau toli nuo pagrindinio šurmulio ir dulkių. Pastatas iškilo šalia 1925 m. įkurto pirmojo Lietuvoje stadiono bei čia buvusios Teniso klubo aikštelės.</p><p><br></p><p>Didesnę kryžiaus formos pastato dalį užėmė pagrindinė salė, perdengta įstiklintomis skliautinėmis gelžbetonio lubomis, sukuriančiomis elegantiškumo ir lengvumo pojūtį. Tokio tipo lubos anuomet laikytos tikra naujove. </p><p><br></p><p>Dvi mažesnės sporto salės sudarė priestatus abiejose pagrindinės konstrukcijos pusėse. Pastato centrinėje dalyje įrengti administraciniai kabinetai ir klasės.  Jose turėjo būti ruošiami fizinio lavinimo pedagogai, kariuomenės instruktoriai, organizuojami įvairūs sporto populiarinimo renginiai ir paskaitos.</p><p><br></p><p>Simetriško tūrio pastatas atitinka italų racionalizmo stilių. Architekto Vytauto Landsbergio-Žemkalnio žodžiai geriausiai apibūdina salės architektūrinį požiūrį: „Projektuodami šį pastatą siekėme sujungti dvi formas viename pastate: susieti klasikinę epochą, kurią reprezentuoja kūno kultūros pradininkė Graikija, su mūsų laikais. Abiejų salių pastatai suprojektuoti klasikine dvasia, modernizuojant tik esminius dalykus, kaip to reikalauja šių dienų architektūra. Tuo pačiu metu siekėme, kad pastatas būtų visiškai modernus“.</p><p><br></p><p>Projekte numatyta, kad pagrindiniu akcentu taps pirmasis Lietuvoje modernus vidaus patalpų baseinas. Iki tol sportininkams tekdavo treniruotis atviruose vandens telkiniuose. Baseinas turėjęs būti itin patrauklus: numatytas apšvietimas iš apačios, galimybė įrengti vasarai atveriamą stiklinį stogą, kad saulė bei grynas oras galėtų patekti į patalpos vidų. Deja, tačiau ekonominei krizei pakoregavus planus, ši idėja įgyvendinta praėjus tik ketvirčiui amžiaus nuo sumanymo pradžios – 1959 m.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/13.jpg', '54.89834740', '23.93457550');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('14', 'Kauno Ąžuolyno sporto statinių komplekso sporto halė', '1939 m., inžinierius Anatolijus Rozenbliumas', 'Perkūno al. 5', '<p>Legendinė sporto halė – pirmoji Europoje pastatyta specialiai krepšiniui. Ją nuspręsta įkurti dar 1937 m., Lietuvos krepšininkams laimėjus Europos krepšinio čempionatą Rygoje. Tuomet paskelbta, kad praėjus dvejiems metams, 1939 m., Europos krepšinio pirmenybės bus rengiamos Kaune.</p><p><br></p><p>Per pusmetį iškilusi Sporto halė pelnė didžiulę šlovę ne tik Lietuvos sportui, bet ir pagrindiniam jos statytojui, garsiam to meto šalies statybų inžinieriui Anatolijui Rozembliumui.</p><p><br></p><p>Techniškai sudėtingo pastato statyba turėjo būti baigta per rekordiškai trumpą laiką, o iššūkių kėlė ir tai, kad didžioji darbų dalis atlikta žiemą. Būta ir tokių atvejų, kai darbininkai betonavo pamatus spaudžiant -20 laipsnių šalčiui, juos šildant specialiais įrenginiais. </p><p><br></p><p>Siekiant sukurti kuo daugiau erdvės, pastato pagrindu pasirinkta skliautinė sistema, susidedanti iš keturių kniedytų arkų, besiremiančių į gelžbetoninius pamatus. Stogo konstrukcijoje tarp arkų sumontuoti trikampio profilio stoglangiai suteikė puikų dienos apšvietimą. </p><p><br></p><p>Besibaigiant pavasariui, 1939 m. gegužę, atidaryta 13 tūkst. vietų halė, kurioje prasidėjo pirmosios treniruotės. Krepšinio aikštelė laikyta geriausia Europoje, tačiau ne visiems patiko griežta, net utilitarinė pastato išorė, gyventojams trūko ornamentikos.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/14.jpg', '54.89743330', '23.93733320');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('15', 'Kino teatras „Romuva“', '1940 m. architektas Nikolajus Mačiulskis', 'Laisvės al. 54', '<p>Tarpukariu centrinė Kauno gatvė – Laisvės alėja – vadinta kino bulvaru dėl čia veikusių dvylikos kino teatrų. Tokį populiarumą lėmė kino prieinamumas visiems gyventojų sluoksniams, leidžiantis pabėgti nuo kasdienybės, „paskanauti“ kitokio gyvenimo, tradicijų ir vaizdų. </p><p><br></p><p>1940 m. balandžio 18 d. atidaryta „Romuva“ – pripažinta erdviausiu, moderniausiu ir originalumu pralenkiančiu ne tik Kauno, Lietuvos, bet ir kai kuriuos Baltijos šalių kino teatrus. </p><p><br></p><p>Pastato istorija prasidėjo 1938 metais, kai verslininkai Antanas ir Petras Steikūnai įsigijo sklypą Laisvės alėjoje. Art Deco „pilaitės“ statybos startavo dar po metų, pagal architekto Nikolajaus Mačiulskio projektą. Pastatas vos per metus iškilo sklypo gilumoje, taip sukuriant jaukią viešąją erdvę kino teatro prieigose.</p><p><br></p><p>Pagrindinis „Romuvos“ simbolis ir pagrindinis akcentas – Art Deco formų fasadas su aukštu stikliniu iliuminuotu bokšteliu, iškilusiu virš prieangio stogelio. Reklama turėjo būti rodoma naujovišku būdu – kintamos spalvos šviesų fone, tačiau prasidėjus karui tam skirtas aparatas įstrigo geležinkelio stotyje. Fasado plotmė profiliuotais apvadais padalinta į kelis tarpsnius su skirtingo dydžio langų gretomis.</p><p><br></p><p>687 vietų kino teatras įrengtas pagal pažangiausius tuometinės kinematografijos reikalavimus: jame sumontuota galinga mechaninė vėdinimo sistema, „Zeis-Kono“ kino aparatūra. Ovali salė, specialūs sienų apmušalai ir įrengti nuožulnūs gelžbetoninių nerviūrų skliautai, suprojektuoti gelžbetonio konstrukcijų pradininko Lietuvoje – inžinieriaus Prano Markūno. Visi sprendimai skirti akustikai gerinti.</p><p><br></p><p>Apvalios kino salės formos atsikartoja ir kitose patalpose: vestibiulyje, koridoriuose, laiptinėje, prieangyje. Šie sprendimai priskiriami tuo metu JAV vyravusiai streamline estetikai, tačiau čia galima rasti ir „tautinio stiliaus“ motyvų. Dar vienas interjero išskirtinumas – visur vyraujantys rombai: ant lubų, grindų, langų, durų.</p><p><br></p><p>Šiandien „Romuva“ – seniausi Lietuvoje veikiantys kino namai, iki šių dienų išlaikę savo pagrindinę funkciją ir išorinę išvaizdą. Pastatas 2020 m. atnaujintas: restauruotas fasadas, langai, durys, kitos autentiškos Art Deco interjero detalės. Didžiojoje salėje įrengta erdvi scena, tinkama šokio, teatro, muzikos pasirodymams ir konferencijoms. </p>', '../../ehl-pastatai69e876cb10bb3.jpg', '54.89775930', '23.91566350');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('16', 'Kristaus Prisikėlimo bažnyčia', '1933–2004 m., architektas Karolis Reisonas', 'Žemaičių g. 31A', '<p>Kauno tarpukario architektūra ilgus metus buvo žmonių nacionalinės tapatybės atspindys. Tai liudija ir pagrindinė Kauno panoramos puošmena – Prisikėlimo bažnyčia – atlaikiusi ne vieną istorinį išbandymą.</p><p><br></p><p>Idėja Kaune pastatyti memorialinę bažnyčią, simbolizuojančią lietuvių tautos atgimimą, dėkingumą Dievui gimė 1922 m. Iniciatyvą įkvėpė votų aukojimo tradicija krikščionių kultūroje, paplitusi kaip liaudies maldingumo forma bei bažnyčių statybos praktika, pirmą kartą pastebėta Austrijoje ir Prancūzijoje XIX a. pabaigoje, plačiau įsitvirtinusi XX a.</p><p><br></p><p>Prisikėlimo bažnyčios projektavimo konkursas paskelbtas 1928 m., numatant tris pagrindinius reikalavimus: šventovė turi būti monumentalios formos, projektuose numatomas tautinis mauzoliejus, o struktūra perteikia lietuvišką dvasią. Sulaukta penkiolikos pasiūlymų, laimėtoju tapo Karolis Reisonas. Prisikėlimo bažnyčiai pasirinkta Žaliakalnio kalva, kad miesto įžymybė būtų gerai matoma iš Kauno centro. </p><p><br></p><p>1933 m. pradėta kloti pastato pamatus ir susidurta su finansiniais sunkumais: ypač brangiai kainavo kertinio akmens pargabenimas iš Alyvų kalno Jeruzalėje, todėl suaktyvėjo aukų rinkimų akcijos. Jų metu visiems norintiems buvo platinami 10 ir 50 centų bei 1 lito aukų-plytų ženkliukai. Tokiu būdu „pagal savo kišenę“ prie bažnyčios statybai reikiamos sumos surinkimo galėjo prisidėti visi gyventojai. Jų dėka suaukota beveik pusė reikiamų finansų.</p><p><br></p><p>Iki 1940 m. spėta pastatyti pastatą su 63 m aukščio bokštu, tačiau bažnyčia taip ir liko neįrengta. 1941 m. okupacinis režimas nacionalizavo bažnyčią. Būsimi maldos namai virto pramonės mašinos dalimi – vokiečių okupacijos metu čia veikė popieriaus fabrikas, kuris vėliau buvo pritaikytas sovietų karinio komplekso įmonei, dar vadintai Radijo gamykla. </p><p><br></p><p>Charakteringos bažnyčios detalės, pavyzdžiui, terasos koplyčia buvo nugriautos, o vietoje jų įkurtos pagalbinės patalpos ir sudėti įvairūs techniniai įrenginiai. Norint bažnyčioje įrengti gamybos linijas, pastato vidus buvo atkirtas gelžbetoninėmis sijomis, praėjimai padalinti į tris aukštus, o centrinė nava – į penkis.</p><p><br></p><p>Netinkuota, bet didinga raudonų plytų struktūra Kauno horizonte dominavo penkiasdešimt metų. Tai buvo nacionalinis simbolis ir įkvepianti nepriklausomybės atkūrimo viltis. Žmonės niekada neprarado tikslo – pastatyti šventovę visai lietuvių tautai. Išsilaisvinę iš priespaudos, jie sparčiai inicijavo rekonstrukciją, simbolizuojančią visų mūsų laimėjimą – nepriklausomos valstybės prisikėlimą.</p><p><br></p><p>Kauniečių ir  miesto svečių akis traukia šventovės fasadas su siaurų langų juostomis. Jos sustiprina veržlumo ir stiebimosi aukštyn įspūdį. Tai pagrindinis miesto panoramos akcentas, savo siluetu šiek tiek primenanti amerikietiškus, laiptuoto pavidalo dangoraižius.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/16.jpg', '54.90264030', '23.91701390');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('17', 'Buvęs Bero Goldbergo gyvenamasis namas (dabar – privatus)', '1937 m., architektas Volfas Brūnas', 'V. Putvinskio g. 52', '<p>1936-aisiais Kauno litvakas Beras (Borisas) Goldbergas įsigijo sklypą prestižinėje Kalnų g. (dabar V. Putvinskio) ir pradėjo šešiabučio namo statybas. Visus darbus prižiūrėjo technikas ir inžinierius Volfas Brūnas. </p><p><br></p><p>Pirminis projektas keletą kartų koreguotas, reikalaujant derinti fasadą su kaimyniniais namais: karnizo, cokolio, langų aukščius daryti viename lygyje, šoninius langus sujungti bendru rėmu. Statybos metu nukrypta nuo plano: virš įėjimo iš gatvės pusės padarytas langelis laiptinės apšvietimui, virš langų atsisakyta dekoratyvinių nišelių, įrengti langai cokolyje.</p><p><br></p><p>Vos per metus iškilęs namas tapo šiuolaikiškos statybos ir moderznimo etalonu, dažnai nušviečiamu periodinėje spaudoje, 1937 m. įtrauktas į premijuotinų sąrašą. </p><p><br></p><p>Namas pasižymi itin paprasta, tarptautiniam modernizmui būdinga simetriška ir proporcinga fasado kompozicija: balta spalva, aiškiomis linijomis, plačiais langais, minimalistiniais „prancūziško“ tipo  balkonais su ornamentinėmis metalinėmis grotelėmis. Įėjimo akcentas – gulsčiomis betoninėmis juostelėmis pridengtas langas. Pastate galima rasti ir santūrius „istorizmo“ elementus. Kiekvienas aukštas turi po du nedidelius trijų kambarių butus.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/17.jpg', '54.90084490', '23.91280630');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('18', 'Buvęs gydytojos Nadieždos Nagornienės namas (dabar – privatus)', '1934 m., Adolfas Netyksa', 'V. Putvinskio g. 54', '<p>1933 metais gydytoja Nadiežda Nagornienė įteikė miesto valdžiai prašymą dėl trijų aukštų gyvenamojo namo statybų dabartinėje V. Putvinskio gatvėje. Architektui keltas reikalavimas, kad kiekvieno aukšto butai būtų projektuojami žmonėms, besiverčiantiems privačia veikla – gydytojams, teisininkams: turėtų atskirus įėjimus iš laiptinės į darbo kabinetus ir laukimo kambarius bei „ūkinius“ – į virtuves.</p><p><br></p><p>Pastato projektas patikėtas architektui Adolfui Netyksai, sukūrusiam kompaktišką, į kvartalą įsiliejantį modernistinį daugiabutį. Nuo statybų pradžios iki pabaigos projektas pakeistas net 3 kartus. Dėl daugybės pažeidimų darbai ne kartą buvo stabdomi, pradėti keli teisminiai procesai dėl savavališkos statybos bei projekto nepaisymo. Net ir pastačius namą, teisminiai ginčai tęsėsi dar dvejus metus.</p><p><br></p><p>Trijų aukštų pastate jaučiami „istorizmo“ architektūros bruožai. Simetriškas fasadas suskaidytas į du erkerius, antrame ir trečiame aukštuose sujungtus balkonais. Centre – aukštas laiptuotas frontonas. Viršus paryškintas profiliuotais karnizais ir apskritomis angelėmis erkeriuose. Pastato išskirtinumas – didelė terasa per visa namo plotą.</p><p><br></p><p>Tarpukariu V. Putvinskio gatvė dėl čia veikusių įvairių valstybių atstovybių buvo praminta ambasadų gatve. Tokį titulą sustiprino ir šis namas – 4-jame bute 1938–1939 m. veikė Vengrijos konsulatas. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/18.jpg', '54.90084880', '23.91257130');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('19', 'Buvęs advokato Kazimiero Škėmos namas (dabar – privatus)', '1933 m., architektai Bronius Elsbergas, Klaudijus Dušauskas-Duž', 'V. Putvinskio g. 60', '<p>Vienu turtingiausių žmonių tarpukariu laikytas advokatas Kazimieras Škėma, 1932 m. nusprendė statytis namą prestižinėje miesto vietoje – Kalnų gatvėje. Namo projektas iš pradžių patikėtas architektui Klaudijui Dušauskui-Duž, statybų eigoje darbus perėmė Bronius Elsbergas.</p><p><br></p><p>Esminis pokytis – dar vieno aukšto pridėjimas. Laikinojoje sostinėje penkiaaukščiai laikyti retenybe, todėl savininkui teko gerokai pavargti, kol gavo Savivaldybės statybos komisijos pritarimą namo, išsiskiriančio iš bendro V. Putvinskio gatvės užstatymo, aukštingumui.</p><p><br></p><p>Statinyje išryškėja modernistinės tendencijos: penki aukštai su asimetriniu fasadu, erkeriai jungiasi prie balkonų, atkartojančių tuos pačius užapvalintus langų įlankų kampus. Pirmame aukšte net du įėjimai, iš kurių vienas – pagrindinis į pastatą, o kitas vedantis į vidinį kiemą. Čia galima rasti ir B. Elsbergo pamėgtas detales: profiliuotus angų įrėminimus, dekoratyvias traukas. Vidiniame fasade akis traukia laužytų formų balkonai, išsidėstę 2–5 aukštuose. Vakarinėje pusėje namas jungiasi su Antano Gylio ligoninės pastatu.</p><p><br></p><p>Užbaigtas pastatas tapo vienu iš moderniojo Kauno veido simbolių. Čia patalpas nuomojosi Čekoslovakijos ir Švedijos delegacijos 1934–1939 m.</p>', '../../ehl-pastatai69e876fa5c3b1.jpg', '54.90087880', '23.91153930');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('20', 'Pastatų komplekso dailininko Antano Žmuidzinavičiaus namas (dabar – A. Žmuidzinavičiaus kūrinių ir rinkinių muziejus)', '1928 m., architektas Vytautas Landsbergis-Žemkalnis', 'V. Putvinskio g. 64', '<p>Tarpukariu prestižinėje Kalnų (V. Putvinskio) gatvėje namus statėsi Lietuvos „grietinėlė“ – inteligentijos atstovai, žymūs visuomenininkai, Lietuvos politiniai veikėjai. Būtent čia, 64 numeriu pažymėtame pastate, 1928 m. įsikūrė dailininkas A. Žmuidzinavičius su šeima. Jam dviaukštį suprojektavo architektas Vytautas Landsbergis-Žemkalnis, o dar po dešimtmečio iškilo ir trečias aukštas.</p><p><br></p><p>Į pastatą atsikraustę šeimininkai pirmąjį aukštą nuomavo studentams, tremtiniams ar nepasiturintiems miesto gyventojams, antrajame gyveno patys. Viršutinis aukštas virto A. Žmuidzinavičiaus kūrybinėmis dirbtuvėmis. Tarpukariu pastate kurį laiką buvo įsikūręs Švedijos konsulatas, 1930 m. jame dirbo Suomijos švedas, rašytojas ir poetas Henris Parlandas.</p><p><br></p><p>Pastatas netaisyklingo plano su dviem laiptinėmis. Akis traukia banguojantys langai ir lenktos formos durys, balkonų tvoreles puošia tulpės motyvai. Intejere taip pat gausu subtilių detalių: ryškiomis spalvomis – žaliai ir raudonai – nudažytos grindys, įgilintos spintos, per skirtingus kambarius atsikartojantys tautiniai motyvai ar kambarį puošiantys spalvoti stiklai. Šios detalės bei visi autentiški baldai išlikę iki pat šių dienų.</p><p><br></p><p>Šiandien memorialinę, o kadaise gyvenamąją, buto erdvę sudarė trys kambariai. Nors patalpos ir nedidukės, tačiau apipintos idomiomis istorijomis. Dailininko žmonos Marijos Putvinskaitės kambaryje buvo įrengtas odontologijos kabinetas, kuriame lankydavosi net tuometinis prezidentas Antanas Smetona. Dukros kambaryje stovėjo baldai, pagaminti pagal jos pačios sukurtus brėžinius.</p><p><br></p><p>Svetainėje vykdavo ne tik kasdienė šeimos tradicija – bendri pietūs, bet ir susitikimai su įvairiais inteligentijos atstovais. Visuose menininko namuose nebuvo užuolaidų. Čia laikytasi požiūrio – gyventi reikia taip, kad nebūtų ko slėpti.</p><p><br></p><p>Pats A. Žmuidzinavičius save vadino „kolekciomanu” ir rinko viską, kas jam darydavo didesnį įspūdį. Viena originaliausių jo kolekcijų – beveik 300 raguotųjų. Būtent čia ir prasidėjo vienintelio pasaulyje Velnių muziejaus ištakos. Šiuo metu ekspozicija perkelta į naują priestatą, kuriame yra daugiau nei 3 tūkst. raganų ir velnių, pagamintų iš įvairiausių medžiagų: keramikos, medžio, odos ar net džiovintų vaisių. </p><p><br></p><p>Nuo 1966 m. name veikia M. K. Čiurlionio dailės muziejaus padalinys – Antano Žmuidzinavičiaus kūrinių ir rinkinių muziejus.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/20.jpg', '54.90088060', '23.91056480');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('21', 'Kauno Švč. Jėzaus Širdies bažnyčia', '1938 m., architektai Algirdas Šalkauskis, Adolfas Netyksa, Pranas Markūnas', 'A. Juozapavičiaus pr. 60', '<p>Nuo XIX a. pabaigos Šančiuose koncentravosi pramonė ir karyba: čia iškilo didžiausias Kauno tvirtovės karinis miestelis, veikė stambus metalo fabrikas, kūrėsi įvairios dirbtuvės. Tai lėmė spartų rajono ir gyventojų  augimą bei maldos namų poreikį.</p><p><br></p><p>Šventovės statybą tarpukariu inicijavo tuometinis parapijos klebonas Mamertas Lumbė. Projektavimo darbai truko kelerius metus: 1935 m. architektas Algirdas Šalkauskis pateikė savo projektą. Manoma, kad dėl nesutarimų su klebonu neužbaigtus projektavimo darbus perėmė architektas Adolfas Netyksa. Modernistinės bažnyčios statyba užbaigta 1937 m., o statinys pašventintas – 1938-aisiais.</p><p><br></p><p>Vos pastatyti maldos namai tapo judraus prospekto puošmena, nors ir neperkrauta dekoro detalėmis. Modernistinė romaninė šventovės architektūra dažniau primena industrinį pastatą, o ne sakralią erdvę. Ji išsiskiria stambiais tūriais, darniai susiliejančiais su urbanistiniu kraštovaizdžiu: pramone, technikos infrastruktūra ir kareivinių kompleksais.</p><p><br></p><p>Bažnyčios pastatas stačiakampio plano, su dviem žemais bokštais, išryškinančiais centrinį fasadą. Proporcingai iškilusios zakristijos, prie šoninių fasadų, pabrėžia minimalistinį eksterjerą. Bažnyčios fasadams būdinga taisyklingų geometrinių figūrų kompozicija: kvadrato formos centrinės durys kontrastuoja su siaurų, stačiakampių langelių vertikalėmis.</p><p><br></p><p>Bažnyčios stogui panaudota moderni gelžbetonio konstrukcija, sukurta inžinieriaus Prano Markūno – tai vienas pirmųjų plonasienės gelžbetonio kevalo konstrukcijos pavyzdžių tarpukario Lietuvoje. Panašūs gelžbetoniniai skliautai panaudoti Kūno kultūros rūmuose ir kino teatre „Romuva“.</p><p><br></p><p>Interjere išsiskiria presbiterijos arką puošianti dailininko Liudo Truikio freska „Angelai“ bei galiniame fasade įkomponuoti Stasio Ušinskio vitražai.</p><p><br></p><p>Bažnyčia nukentėjo per bombardavimus: išdužo galiniame fasade palikta įstiklinta plokštuma, apgadintas altorius.  1942 m. altorius bei galinė siena pertvarkyta architekto Broniaus Elsbergo.</p><p><br></p><p>Šančių Švč. Jėzaus Širdies bažnyčia – charakteringas, santūrios moderniosios sakralinės architektūros pavyzdys, turintis romaninės dvasios. Modernistinių formų bažnyčios nėra dažnas reiškinys Pirmosios Respublikos laikotarpiui, todėl tai itin įdomus ir vertingas objektas sakralinio paveldo kontekste.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/21.jpg', '54.87168000', '23.93847740');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('22', '„Tulpė“ kooperatyvo namas (dabar – privatus)', '1926 m, inžinierius Antanas Macijauskas', 'A. Mickevičiaus g. 15', '<p>Kauno širdyje stovi įspūdingas trijų aukštų mūrinis „Tulpės“ namas – vienas pirmųjų kooperatyvinių daugiabučių Lietuvoje. Namas iliustruoja ankstyvąsias lietuviškojo „tautinio“ stiliaus paieškas, grįstas liaudies motyvų atkartojimu.</p><p><br></p><p>Inžinieriaus Antano Macijausko 1925 m. suprojektuotas stačiakampio plano pastatas, kiekviename aukšte turėjo du erdvius, po penkis kambarius turinčius butus. Dekoro elementai kurti pagal savitą architekto „tautiškumo“ formulę – atsisakyta neobarokinių formų, dėmesys sutelkiamas į liaudies kūrybos motyvus.</p><p><br></p><p>Žvilgsnį traukia puošnus fasadas, alsuojanti liaudies meno įkvėpta estetika – čia dominuoja amatininkų naudotos ornamentikos interpretacijos: stilizuotos tulpelės, žvaigždutės, dantukai. Iš molio ir tinko formuoti dekorai novatoriškai siekė perteikti medžio drožybos tradiciją. Tiesa, nepraėjus nė dešimtmečiui, kritikai liaudies motyvų perkėlimą į šiuolaikines medžiagas pradėjo vertinti skeptiškai, teigdami, kad „1925–1926 metais Kaune vienas, tiesa ne architektas, bandė išreikšti mūre ir tinke medinius ornamentus, bet sukūrė karikatūrą.“</p><p><br></p><p>Puošniausia centrinė namo dalis, išskirianti plačiu rizalitu. Laužytos formos frontono centre apskritas saulutę primenantis langelis. Po juo – pusmėnulio formos laiptinės švieslangis. Kitus langus puošia sudėtingo kontūro sandrikai. Trečias aukštas atskirtas dekoratyviniu bangelių karnizu ir frontonu. </p><p><br></p><p>„Tulpės“ namas išlieka drąsiu Kauno architektūriniu eksperimentu – tautinio stiliaus manifestu bei kultūrinio bei estetinio dialogo su praeitimi ir modernybe liudytoju. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/22.jpg', '54.89616680', '23.91719280');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('24', 'Buvęs Prano Gudavičiaus ir Aleksandros Iljinienės namas', '1933 m. architektas Arnas Funkas', 'K. Donelaičio g. 19', '<p>Dviejų aukštų gyvenamasis Aleksandros ir Jurgio Iljinų namas – vienas ryškiausių tarpukario Lietuvos modernizmo šedevrų ir Kauno ikona. Sklypą kartu su architekto Arno Funko projektu 1933-aisiais J. Iljinas įsigijo iš karo gydytojo Prano Gudavičiaus ir padovanojo žmonai Aleksandrai. Įspūdingas faktas – statybos užbaigtos vos per dešimt mėnesių!</p><p><br></p><p>Namas išsiskiria architektūrine drąsa – čia dominuoja laisva, novatoriška langų kompozicija: kampiniai langai, lenkto stiklo segmentai, išraiškingas apvalus langas, įkomponuotas į išsikišantį erkerį virš 5 metrų aukščio įėjimo durų. Namas išsiskyrė ir savo prabangiu bei išskirtiniu Art Deco stiliaus interjeru.</p><p><br></p><p>Antrame aukšte įsikūrė namo šeimininkai Iljinai. Butas pasižymėjo ypatinga prabanga ir rytietiška dvasia: interjerą ir baldus suprojektavo pats A. Funkas. Čia išlikusi niša su tradicine muqarnas – dekoratyvine struktūra, dažna islamo architektūroje.</p><p> </p><p>Pastate gausu iš kitų autentiškų detalių – spiraliniai mediniai laiptai, vitražinės durys, arkinės angos su medinėmis dailylentėmis, subtilus lubų dekoras. Viršuje sukurta rekreacinė terasa su nedidele oranžerija-„žiemos sodu“, matomu per holo stiklines lubas. Deja, bet viena labiausiai viliojančių namo detalių – neišliko.</p><p><br></p><p>Pirmame aukšte buvo įrengti du nuomojami butai. Juose tarpukariu gyveno Mykolas Golbinderis ir Jurgis Matulaitis, rūsyje – Grigorijus Ickavičius. Antrojo pasaulinio karo metu, 1941-aisiais, pastatas buvo nacionalizuotas. Iljinams pasitraukus į Vokietiją, jų bute apsigyveno žinoma dainininkė Gražina Matulaitytė su vyru, žurnalistu ir poetu bei M. K. Čiurlionio dailės darbų tyrinėtoju Aleksiu Rannitu. </p><p><br></p><p>Sovietmečiu čia veikė įvairios organizacijos, tarp jų – Laisvanoriškos pagalbos armijai, aviacijai ir laivynui draugija, taip pat priešgaisrinės apsaugos tarnyba.</p><p><br></p><p>2018 m. pastatas kruopščiai restauruotas, atkuriant tarpukario modernizmo dvasią. Atidžiai išlaikytos proporcijos, eksterjero ir interjero detalės: grakščios langų formos, medžio elementai, Art Deco stiliaus užuominos. Anksčiau pilkas fasadas šiandien puošiasi atkurtomis šviesiomis spalvomis.</p><p><br></p><p>Išskirtinį pastatą galima apžiūrėti privačių ekskursijų metu.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/24.jpg', '54.89848740', '23.92219800');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('25', 'Buvęs Burmistro Jono Vileišio namas (dabar – privatus)', '1930 m., architektas Aleksandras Gordevičius', 'V. Putvinskio g. 68', '<p>Ryškų pėdsaką tarpukario Kauno modernizacijoje paliko ilgametis miesto Burmistras – Jonas Vileišis, miestui vadovavęs 1921–1931 m. Jo pastangų dėka Kaunas virto europinio lygio miestu: įvesta kanalizacija ir vandentiekis, asfaltuotos gatvės, pastatyti nauji tiltai, sukurta moderni viešojo transporto sistema, įrengti funikulieriai, iškilo tūkstančiai naujų pastatų. Idėjų Burmistras sėmėsi ir iš JAV bei Europos miestų, besilankant diplomatinėse kelionėse. </p><p><br></p><p>Gyvenamojo namo statybą prestižinėje V. Putvinskio gatvėje J. Vileišis inicijavo savo sklype. Dalį pastato paskyrė nuomai. Ypatingą reikšmę namas įgijo 1934–1938 m. – čia veikė Jungtinių Amerikos Valstijų pasiuntinybė, kuriai vadovavo nepaprastasis pasiuntinys ir įgaliotasis ministras Owen J. C. Norem. Išnuomojęs namą pasiuntinybei, savininkas 1932 m. persikėlė gyventi į sklypo gilumoje pastatytą namą (dab. V. Putvinskio g. 66).</p><p><br></p><p>Buvo parengti net keli pastato projektai, kol apsistota ties esamu variantu. Statybos techninę priežiūrą vykdė architektas Aleksandras Gordevičius, kuris, manoma, buvo ir galutinis projekto autorius.</p><p><br></p><p>Pastato architektūroje ryškūs modernizmo ir vadinamosios „amerikietiškos“ streamline estetikos bruožai. Stambus trijų aukštų pastatas sudarytas iš dviejų laužytos konfigūracijos korpusų – didžiojo, orientuoto į gatvę, ir siauresnio, esančio kiemo pusėje. Pagrindinės reprezentacinės patalpos sukurtos aplink centrinį holą, o natūraliai šviesai užtikrinti prie ugniasienės įrengtas vadinamasis „šviesos šulinys“.</p><p><br></p><p>Pagrindinis įėjimas į pastatą įrengtas šone, nuo įvažiavimo į kiemą. Raiškiausiu eksterjero akcentu tapo įtrauktas ir paaukštintas kampas su suapvalintais balkonais, formuojančiais aptakų pastato siluetą. Kampinė dalis viršutiniuose aukštuose dekoruota grafiškomis horizontaliomis juostelėmis, o gatvės fasado skaidymą pabrėžia profiliuotomis traukomis įrėmintos tarpaukščių juostos.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/25.jpg', '54.90096030', '23.91037030');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('26', 'Buvusi Lietuvos Respublikos Ministro Pirmininko Juozo Tūbelio vila (dabar – Kauno dailės gimnazija)', '1933 m., architektas Feliksas Vizbaras', 'Dainavos g. 1', '<p>Viena įspūdingiausių Kauno tarpukario modernizmo vilų – buvusi Lietuvos Ministro Pirmininko Juozo Tūbelio rezidencija, iškilusi ant Žaliakalnio šlaito keteros, netoli Kauko laiptų. Pastatas suprojektuotas taip, kad natūraliai įsilietų į reljefą ir maksimaliai išnaudotų atsiveriančią Kauno panoramą.</p><p><br></p><p>Namas, kuriame gyveno J. Tūbelis su žmona, visuomenės veikėja Jadvyga Chodakauskaitė-Tūbelienė, pasižymi asimetriška ir dinamiška kompozicija. Architektas F. Vizbaras sukūrė modernistinę, tačiau kartu reprezentatyvią vilą – mūrinį, tinkuotą dviejų ir trijų aukštų pastatą su pusapskrite veranda, balkonu, terasa ir šlaitiniu stogu.</p><p><br></p><p>Griežtas geometrines formas papildo tamsaus tinko langų apvadai, karnizai ir verandos detalės. Vieni ryškiausių akcentų – puscilindrė veranda ir kampinis bokštelis, suteikiantys pastatui lengvo monumentalumo. Pastato planas – laisvos struktūros: patalpos išdėstytos aplink centrinį holą su laiptais, o pagrindiniai kambariai, atsiveriantys į šlaitą, sujungti į erdvią reprezentacinę salę, skirtą priėmimams ir oficialiems susitikimams.</p><p><br></p><p>Tarpukariu vila tapo ne tik šeimos namais, bet ir svarbiu politinio bei visuomeninio gyvenimo centru. Čia rinkdavosi Kauno inteligentija, užsienio diplomatai, svarbūs valstybės veikėjai, ir, žinoma, Prezidentas Antanas Smetona su šeima. Svarbius vyrus draugėn suvedė žmonų giminystė – Sofija Smetonienė ir Jadvyga Tūbelienė buvo seserys. Jų pokalbiuose skambėjo drąsūs raginimai  Lietuvos moterims – balsuoti. Tuomet net Prancūzijoje ar Italijoje moterys balsavimo teisės dar neturėjo.</p><p><br></p><p>Vilos interjeras atspindėjo aukštą šeimininkų statusą – erdvūs kambariai, prabangūs baldai, meno dirbiniai kūrė reprezentacinę aplinką.</p><p><br></p><p>Namas nacionalizuotas sovietinės okupacijos pradžioje, o nuo 1946 m. jame įsikūrė dailės mokykla, šiandien žinoma kaip Kauno dailės gimnazija. Funkcionalus ir estetiškai išraiškingas pastatas puikiai tinka kūrybinei veiklai.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/26.jpg', '54.90081820', '23.92410060');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('27', 'Buvęs rangovo Miko Grodzenskio namas  (dabar – privatus)', '1929 m., architektai Edmundas Frykas, Mikas Grodzenskis', 'K. Donelaičio g. 17', '<p>Vienas ankstyviausių modernizmo stiliaus gyvenamųjų namų Kaune buvo pastatytas K. Donelaičio gatvėje. Jo savininkas ir statytojas buvo rangovas Mikas Grodzenskis, kuris kartu su architektu Edmundu Fryku parengė projektą ir prižiūrėjo statybas.</p><p><br></p><p>Pastatas išsiskiria paprasta ir santūria architektūra. Vyrauja aiškios geometrinės formos, lygūs paviršiai, beveik nėra dekoracijų. Toks sprendimas atspindi ankstyvojo modernizmo principus – funkcionalumą ir racionalumą.</p><p><br></p><p>Namo planas apgalvotas ir patogus. Jame buvo ne tik gyvenamosios patalpos, bet ir savininko kontora. Įėjimas iš gatvės vedė į pirmojo aukšto kabinetą, sujungtą su butu. Tuo tarpu pagrindinis įėjimas į gyvenamąsias patalpas buvo paslėptas giliau, įvažos pusėje, taip atskiriant gyvenamąją erdvę nuo gatvės triukšmo.</p><p><br></p><p>Kotedžo tipo namas – asimetriškas, su laiptuotu, „laužytu“ fasadu. Jis šiek tiek atitrauktas nuo gatvės linijos, o tai suteikia pastatui dinamiškumo. Pirmajame fasado įgilinime įrengtas įėjimas ir balkonas, o kitame – įvaža į kiemą.</p><p><br></p><p>Išskirtinis šio namo bruožas – užnugaryje suformuotas vadinamasis „itališkas kiemelis“. Tai nedidelė, nuo aplinkos aukšta tvora atskirta erdvė su grindiniu ir terasa – retas ir įdomus sprendimas Kauno architektūroje.</p><p><br></p><p>Ryškiausia pastato detalė – kampiniai langai, būdingi ketvirtojo dešimtmečio modernizmui. Jie suteikia fasadui lengvumo, daugiau šviesos ir pabrėžia modernų pastato charakterį.</p><p><br></p><p>Tai naujų architektūrinių idėjų sklaidos liudijamas, apimantis tiek privataus užsakovo, tiek ir profesionalaus statybos rangovo ambicijas kurti šiuolaikišką bei funkcionalią architektūrą.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/27.jpg', '54.89848510', '23.92242680');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('28', 'Buvęs inžinieriaus Antano Gravrogko namas (dabar – privatus)', '1932 m., architektas Edmundas Frykas', 'V. Putvinskio 70', '<p>Žymaus tarpukario visuomenės veikėjo, inžinieriaus ir Kauno Burmistro Antano Gravrogko namas pastatytas 1932 metais. Tai vienas iš nedaugelio gyvenamosios paskirties pastatų, suprojektuotų architekto Edmundo Fryko, išsiskyrusio savitu braižu Lietuvos architektūroje. Pastatas atspindi jam būdingą modernizmo ir istorizmo tendencijų sintezę.</p><p><br></p><p>Keturių aukštų namas išsiskiria puošniu dekoru, čia matomi istorizmo ir Art Deco bruožai. Pagrindinis fasadas suskaidytas į vertikalias dalis, kiekviena jų įkomponuota skirtingai. Tris apatinius aukštus pabrėžia laužytų formų iškyšos, pasibaigiančios virš trečiojo aukšto įrengta terasa su klasikinių formų baliustrada. Ši terasa sujungia žemesnę centrinę dalį su aukštesnėmis šoninėmis fasado dalimis.</p><p><br></p><p>Kairioji fasado dalis, ties įvažiavimu į vakarinę sklypo dalį, užapvalinta, o dešinėje pusėje įrengtas pagrindinis įėjimas. Nors jis nėra architektūriškai ryškiai akcentuotas, tačiau išsiskiria menine puošyba – 1933 m. skulptoriaus Juozo Zikaro sukurtais bronziniais bareljefais „Arklių tramdytojas“, „Pjovėjas“ ir „Rinkėja“, vaizduojančiais liaudiškus agrarinius ir mitologinius motyvus. Liaudies meno įtaką atspindi ir antrojo bei trečiojo aukštų balkonų augaliniai ornamentai.</p><p><br></p><p>Kiekviename aukšte buvo įrengta po vieną, gana sudėtingo plano, butą. Ant stogo įrengta terasa, vainikuojama baliustrada ir dekoratyvia dantytų kuorų „karūna“. Kiemo fasade išlikę erkerių tipo „kabančios“ šaltosios spintos – būdingas daugelio Kauno tarpukario gyvenamųjų namų architektūros elementas. </p><p><br></p><p>Šis pastatas iki šiol laikomas vienu ryškesnių dekoratyvios tarpukario architektūros pavyzdžių Kaune.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/28.jpg', '54.90095320', '23.91012850');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('29', 'Buvęs verslininkų Mozės ir Malkos Chaimsonų namas (dabar – privatus)', '1930–1931 m., architektas Vytautas Landsbergis-Žemkalnis', 'Maironio g. 13', '<p>Mozė Chaimsonas – audinių sandėlio bendrasavininkas – kartu su broliu nusprendė pasistatyti namą ir projekto įgyvendinimui pasirinko neseniai Romoje studijas baigusį architektą Vytautą Landsbergį-Žemkalnį. 1930 m. Kauno centre iškilo itin modernus daugiabutis, tapęs aukščiausiu gyvenamuoju pastatu mieste – „dangorėžiu“.</p><p><br></p><p>Pabrėžtinai asketiškų formų eksterjeras buvo neįprastas tarpukario Lietuvos architektūroje. Pagrindinio fasado kompozicija grindžiama proporcijų pusiausvyra: simetrijos centrą išryškina nuo antrojo aukšto kylantis platus erkeris ir atikinis aukštas.</p><p><br></p><p>Lakonišką portalą su viršlangiu jungia lengvai profiliuotas granitinio tinko apvadas. Aukštas cokolis, ryškūs karnizai ir platūs, į vertikalias skiltis suskirstyti, įvairaus dydžio langai kuria horizontalių linijų ritmiką. Kampiniai erkerio langai įstiklinti lenktais stiklais.</p><p><br></p><p>Namo planas – stačiakampis, su banguoto kontūro rizalitu kiemo pusėje. Tai būdinga trečiojo XX a. dešimtmečio daugiabučiams. Pastate įrengtos dvi laiptinės: pagrindinė – su liftu ir ūkinė, paslėpta už stiklinės sienelės.</p><p><br></p><p>Pirmuosiuose trijuose aukštuose suprojektuota po du prabangius butus su erdviais prieškambariais, holais, dvipusiu patalpų išdėstymu ir tiesiogine jungtimi su salonais bei valgomaisiais. Ketvirtajame ir penktajame aukštuose – po keturis mažesnius butus.</p><p><br></p><p>Pusrūsyje ir atikiniame mezonine įrengtos gyvenamosios patalpos aptarnaujančiam personalui – tiek pastato apačioje, tiek viršuje esančios erdvės anuomet nebuvo laikomos prestižinėmis.</p><p><br></p><p>Chaimsonų šeima gyveno bute trečiajame aukšte, o vieną iš penktojo aukšto butų nuomojosi garsus dailininkas ir scenografas Mstislavas Dobužinskis.</p><p><br></p><p>Savo modernumu, funkcionalumu ir patogumu pastatas iki šių dienų gali būti lyginamas su šiuolaikiniais Kauno daugiabučiais. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/29.jpg', '54.89692670', '23.90929530');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('30', 'Buvęs Vinco ir Onos Tercijonų namas (dabar – privatus)', '1936 m., architektas Bronius Elsbergas', 'V. Putvinskio g. 72', '<p>Prestižiniame kvartale aplink Kalnų gatvę tarpukariu namus statėsi žinomi visuomenės veikėjai, gydytojai ir teisininkai, o pastatai formavo harmoningą architektūrinę visumą. Gatvės gale stovintis Vinco ir Onos Tercijonų namas, priklausomai nuo žiūrėjimo krypties, šį ansamblį tarsi pradeda arba užbaigia.</p><p><br></p><p>Pastatas išsiskiria neįprasta dvilype sandara ir jautriu prisitaikymu prie Žaliakalnio šlaito reljefo. Iš gatvės pusės jis atrodo kaip kompaktiškas, trijų aukštų modernistinis miestietiškas namas, o iš kiemo – primena sodybinio tipo statinį: dalį trečiojo aukšto dengia aukštas šlaitinis stogas, o pirmasis aukštas įleistas į šlaitą, sutvirtintą atramine siena su siaura terasa.</p><p><br></p><p>Pastato kompozicija asimetriška, formos lakoniškos. Gatvės fasade dominuoja platūs langai, kampinis antrojo aukšto erkeris ir per visą fasadą besitęsiantys balkonai. Jų suapvalinti kampai sušvelnina griežtas stačiakampes formas ir suteikia pastatui modernistinio lengvumo.</p><p><br></p><p>Vidaus planas buvo funkcionalus ir pritaikytas gyventojų poreikiams. Pirmajame ir antrajame aukštuose įrengta po du panašiai suplanuotus butus, o antrasis ir trečiasis aukštai sujungti vidiniais laiptais į vieną būstą. Jame gyveno namo savininkai – vaikų gydytojas Vincas Tercijonas su žmona Ona. </p><p><br></p><p>Namas buvo pritaikytas gydytojo privačiai praktikai: prie įėjimo atskirtos lankytojams skirtos patalpos, bendrose laiptinėse įrengti sanitariniai mazgai. Ne mažiau svečių sulaukdavo ir Ona Putvinskaitė-Tercijonienė – pedagogė, visuomenės veikėja, Lietuvos šaulių sąjungos narė nuo pat jos įkūrimo, rūpinosi sanitarija, švietimu, leidyba, vaikų ugdymu, organizaciniais darbais, vadovavo Kauno moterų šaulių veiklai ir priklausė nacionaliniam moterų komitetui.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/30.jpg', '54.90093530', '23.90984580');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('31', 'Gydytojų Paulinos Kalvaitytės ir Vlado Lašo namas (dabar – privatus)', '1933 m., architektas Stasys Kudokas', 'Laisvės al. 3', '<p>Pačioje Laisvės alėjos pradžioje, ties sankirta su Trakų gatve ir laiptais į Vytauto parko šlaitą, stovintis pastatas traukia dėmesį savo neįprastu – „nyderlandišku“ – fasadu. Retam kauniečiui žinoma, kad už neįprastai storų pastato sienų veikė vienas pirmųjų Lietuvoje rentgeno aparatų.</p><p><br></p><p>1933-aisiais, pagal S. Kudoko projektą, iškilęs pastatas dekoratyvus ir išraiškingas: arkinius apvadus puošia stilizuoti „tulpelių“ motyvai, o langų rėmai išryškinti balta spalva, kontrastuojančia su tamsiu fonu. Čia nėra įprasto cokolio – pakeltos sienos paslepia dvišlaitį stogą. Nors viršuje matomas laiptuotas siluetas, bendras įspūdis išlieka vientisos plokštumos: joje išsiskiria centrinė ašis ir aukštas laiptinės langas, akcentuotas liaunų arkų reljefu.</p><p><br></p><p>Namas stačiakampio plano, simetriškas, koridorinio dvipusio išplanavimo, su dviem laiptinėmis. Viena jų – paradinė, kita – ūkinė, esanti kiemo pusėje. Prie pastarosios įrengti balkonai, o pati laiptinė skirta aptarnaujančiam personalui: ja judėdavo tarnaitės, gabendavo skalbinius ir kitus ūkio reikmenis, taip išlaikant reprezentacinių erdvių tvarką.</p><p><br></p><p>Pastatas priklausė žymiems gydytojams – Kauno klinikų kūrėjui profesoriui Vladui Lašui ir vienai pirmųjų Lietuvos rentgenologių Paulinai Kalvaitytei-Karvelienei. Pirmajame aukšte veikė jos privatus rentgeno kabinetas – jame naudotas vienas pirmųjų rentgeno aparatų Lietuvoje. Ji taip pat vadovavo Kauno miesto ligoninės rentgeno skyriui ir dėstė Vytauto Didžiojo universiteto Medicinos fakultete. </p><p><br></p><p>1938-aisiais namą perėmė Lietuvos gydytojas fiziologas, alergologijos pradininkas Lietuvoje, politinis bei visuomenės veikėjas Vladas Lašas.  Pats profesorius čia negyveno. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/31.jpg', '54.89659410', '23.92673760');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('32', 'Verslininkės Minos Kotkauskienės namas (dabar – privatus)', '1930 m., Bronius Elsbergas', 'Laisvės al. 69', '<p>Pačioje Laisvės alėjos širdyje stovi namas, kurį daugelis praeina nė nepakeldami akių. Iš pirmo žvilgsnio jis atrodo paprastas, tačiau pakanka pažvelgti aukštyn ir pastatas atgyja: jo fasadas ima judėti, lūžinėti, banguoti.</p><p><br></p><p>Šį nepaprastą įspūdį kuria zigzagu laužyta siena ir iš jos į priekį išsikišę balkonai. Tarpaukščių juostos dar labiau pabrėžia kampuotą ritmą, o viršuje fasadą vainikuoja parapetinis frizas. Tai ekspresionistinė Art Deco estetika.</p><p><br></p><p>Namas iškilo 1930-aisiais – verslios moters, Minos Kotkauskienės, užsakymu. Ji netoliese valdė kino teatrą „Olimp“, kurį vėliau pervadino „Rambynu“.</p><p><br></p><p>Pastatas atitiko to meto Laisvės alėjos tradiciją: pirmasis aukštas skirtas prekybai, o viršutiniai – gyvenimui. Čia veikė keturios parduotuvės su atskirais įėjimais iš gatvės, o aukščiau – įrengti keturi butai. Laiptinė viena, siaura, kukli, su langu į kiemą.</p><p><br></p><p>Laikui bėgant namas tapo ne tik architektūriniu, bet ir kultūriniu liudininku. 1942–1949 metais čia gyveno Lietuvos operos dirigentas, kompozitorius, pedagogas, muzikas ir visuomenininkas Juozas Tallat-Kelpša, tuo metu vadovavęs netoliese esančiam Kauno valstybiniam dramos teatrui. Ant pastato kabo jam skirta memorialinė lenta su bareljefu.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/32.jpg', '54.89724990', '23.91095000');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('33', 'Taubės-Fiegės Elšteinienės namas (dabar – Lietuvos Respublikos Vyriausybės atstovo būstinė)', '1935 m., architektai Leiba Zimanas, Izaokas Trakmanas', 'L. Sapiegos g. 4', '<p>Dabartinėje L. Sapiegos gatvėje tarpukariu iškilo modernus ir elegantiškas namas, priklausęs Taubei-Fiegei Elšteinienei. Jį suprojektavo architektai Leiba Zimanas ir Izaokas Trakmanas. Pastatas tapo išskirtiniu miesto akcentu dėl santūraus, bet išraiškingo, Bauhauzo bruožus atspindinčio fasado.</p><p><br></p><p>Baltą plokštumą ritmingai suskaidė siauri langai, kuriuos papildė kontrastinga tamsaus tinko juosta. Kampinė lodžija su kolona suteikė namo kompozicijai išskirtinumo – nors pirminiame sumanyme čia turėjo atsirasti skulptūra. Vėliau, dėl praktiškumo, pastatas papildytas trečiu aukštu.</p><p><br></p><p>Viduje įrengti penki butai: pirmame ir trečiame aukštuose – po du nedidelius, o antrame – erdvūs savininkų apartamentai. Namo šeimininkės vyras Mozė Elšteinas Kaune valdė parfumerijos ir kosmetikos parduotuvę, todėl šeima gyveno itin patogiai ir moderniai.</p><p><br></p><p>Vos pastatytas, namas sulaukė pripažinimo – 1936 metais, Kauno Burmistrui pavedus, Statybos skyrius jį premijavo kaip gražiausią gyvenamojo namo fasadą. Tai rodė ne tik architektų talentą, bet ir modernėjantį visuomenės estetinį skonį.</p><p><br></p><p>Vėliau, sovietmečiu, pastatas nacionalizuotas ir pritaikytas administracinėms reikmėms. Šiandien jis tebėra svarbi Kauno architektūros dalis, kurioje pastaraisiais metais veikia Vyriausybės atstovo Kauno apskrityje būstinė.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/33.jpg', '54.89855540', '23.90635740');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('34', 'Elijošiaus Šneiderio namas (dabar – privatus)', '1938 m., architektas Stasys Kudokas', 'Vaidilutės g. 3', '<p>Išskirtinis daugiabutis gyvenamasis namas Kaune iškilo nedideliame akligatvyje tarp Kęstučio ir Miško gatvių. 1938-aisiais pastatytas keturių aukštų namas iš karto patraukia dėmesį elegantiška architektūra ir subtiliai subalansuotomis proporcijomis. Šiandien jis pelnytai gali būti laikomas vienu ryškiausių brandžiojo tarpukario modernizmo pavyzdžių.</p><p><br></p><p>Jo statyba tetruko vos pusmetį. Siekiant vizualiai sumažinti pastato aukštį, ketvirtasis aukštas suprojektuotas siauresnis nei apatiniai, taip sukuriant lengvesnį siluetą.</p><p><br></p><p>Pastatas pasižymi mansardiniu stogu, asimetriška kompozicija bei išsikišusiais tūriais, suteikiančiais jam dinamiškumo. Fasaduose dominuoja horizontalūs, užapvalintų formų balkonai, kurie kuria lengvumo ir grakštumo įspūdį. Ypatingu akcentu tampa erkeris su siaurais langais ir dekoratyviniais karnizais, pabrėžiantis laiptinės vertikalę.</p><p><br></p><p>Architekto S. Kudoko projektuotame name įrengta vienuolika erdvių ir patogių butų – kiekviename aukšte po du, trijų ir keturių kambarių. Interjeruose buvo išlaikytas funkcionalumas: reprezentaciniai kambariai sujungti suveriamomis durimis, o kiemo pusėje prie virtuvių įrengti tarnaičių kambariai. Įdomu tai, kad tarnaitėms čia skirtas išskirtinis dėmesys – jų kambariai turėjo net atskirus balkonėlius. Pastate taip pat įrengtas liftas, atsisakyta atskiros ūkinės laiptinės – visi gyventojai ir personalas naudojosi viena bendra erdve.</p><p><br></p><p>S. Kudokas čia, kaip ir kituose pastatuose, kūrė vientisą architektūrinę kalbą – subtiliai taikė dekoro motyvus: fasadą papuošė rozetės su gėlių ornamentais, primenančios jo kurtos Kauno karininkų ramovės interjero detales.</p><p><br></p><p>Elijošius Šneideris ir jo šeima pasidžiaugti naujuoju būstu galėjo trumpai – 1941 metais sovietų valdžia juos ištremė į Tomsko sritį. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/34.jpg', '54.89478510', '23.92302410');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('35', 'Česlovo Pacevičiaus vila (dabar – privatus)', '1934 m., architektas Vsevolodas Kopylovas', 'Vydūno al. 59', '<p>Nedidelė, tačiau išraiškinga vila Žaliakalnyje – vienas iš nedaugelio minimalistinės architektūros pavyzdžių tarpukario Kaune. Stačiakampio plano, vieno aukšto gyvenamasis namas išsiskiria lakoniška forma ir preciziškai subalansuotomis proporcijomis. Jo architektūroje atsispindi modernizmo principai, kuriuos propagavo žinomas architektas, akademikas ir interjero dizaineris Ludwig Mies van der Rohe.</p><p><br></p><p>Pagrindinis namo fasadas itin paprastas ir simetriškas: centre įrengtos durys, o abipus jų – du dideli langai. Įėjimo niša švelniai įgilinta, link durų veda užapvalinti kampai dekoruoti gelsvomis keraminėmis plytelėmis. Portalą papildo subtilus horizontalus stogelis ir siauras karnizas, o langus įrėmina nežymiai iškilūs tinko apvadai, spalviškai derantys prie keramikos. Net šoniniuose fasaduose esančios ventiliacijos angos tampa dekoratyviais, grafiškais elementais.</p><p><br></p><p>Pastatas asketiškas, tačiau monumentalumo įspūdį kuria stambus mastelis ir švarios, neapkrautos plokštumos. Iš gatvės pusės susidaro plokščio stogo įspūdis, nors iš tiesų stogas yra vienšlaitis, su nedideliu nuolydžiu į kiemo pusę, paslėptas už paaukštintų parapetų.</p><p><br></p><p>Aplinką papildo subtiliai suprojektuota tvora su įstrižai sukaltomis lentomis – tarp jų krentantys šešėliai suteikia dinamiškumo. Įėjimą pabrėžia mūriniai vartų stulpai ir lengva vijoklių pergolė (lauko pavėsinė), kuri kartu su pastatu sudaro vientisą architektūrinį ansamblį.</p><p><br></p><p>Namo viduje architektas suplanavo kompaktišką, tačiau funkcionalų trijų kambarių butą. Tarpukariu interjeras, kaip ir išorė, pasižymėjo paprastumu ir racionalumu: reprezentacinės erdvės orientuotos į gatvę, o pagalbinės – į kiemą.</p><p><br></p><p>Vila pastatyta Žaliakalnyje – tarpukariu formuotame gyvenamųjų namų ir miesto-sodo rajone, kuriame vyravo laisvo užstatymo principai. Čia minimalistinė modernistinė architektūra ryškiai kontrastavo su aplinkinėmis tradicinėmis vilomis ir kūrė naują estetinę kryptį.</p><p><br></p><p>Pastatas buvo įvertintas ir oficialiai: 1935 m. Kauno miesto taryba skyrė jam premiją „už gražiausią ir patogiausią mūrinį namą“</p>', 'https://modernist.kaunas.lt/ehl-pastatai/35.jpg', '54.90385020', '23.94711850');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('36', 'Juozo Daugirdo gyvenamasis namas (dabar – privatus)', '1930 m., architektas Vladimiras Dubeneckis', 'Vytauto pr. 30', '<p>Bendrovės „Drobė“ direktoriaus, Amerikos lietuvio Juozo Daugirdo iniciatyva Vytauto prospekte iškilo keturių aukštų daugiabutis su prekybos patalpomis. Jis buvo skirtas nuomai ir tarpukariu tapo vienu ryškesnių šios miesto arterijos akcentų. V. Dubeneckio vėlyvasis projektas atskleidžia architekto posūkį nuo klasikinės architektūros link modernios.</p><p><br></p><p>Pastato tūris simetriškas, formuojamas apie centrinėje ašyje išdėstytą laiptinę ir liftą. Pagrindiniame fasade išraiškingi du stambūs erkeriai, kuriuos kerta juostiniai, smulkiai vertikaliai sudalyti langai. Virš jų iškilę atikiniai aukštai pabrėžia centrinės dalies pagilinimą. </p><p><br></p><p>Nors bendroje namo kompozicijoje vyrauja modernizmas, kai kuriose detalėse galima įžvelgti ir architektui būdingų bruožų – įėjimą puošia stilizuoti tautinio stiliaus ornamentai, vadinamosios „liaudiškos tulpės“.</p><p><br></p><p>Pirmasis pastato aukštas buvo skirtas komercijai – čia veikė parduotuvės su didelėmis vitrinomis, laikytomis techniniu pasiekimu tarpukario Lietuvoje. Antrajame–ketvirtajame aukštuose įrengta po du erdvius penkių kambarių butus, o pastogėje – kuklesni būstai. Daugirdų šeima gyveno trečiajame aukšte. Butų išplanavimas funkcionalus – reprezentacinės patalpos orientuotos į Vytauto prospektą, o miegamieji ir ūkinės paskirties patalpos į ramesnę kiemo pusę.</p><p><br></p><p>Namas tapo svarbus ir urbanistine reikšme. XX a. 3-iajame dešimtmetyje ši Vytauto prospekto atkarpa buvo itin kontrastinga – greta mūrinių pastatų stovėjo mediniai, menkos reputacijos namai. Daugirdo namas tapo savotišku miesto modernėjimo simboliu, prisidėjusiu prie rajono transformacijos į reprezentacinį gyvenamąjį kvartalą. Pastate kurį laiką gyveno Prancūzijos konsulas Paul Py, kas dar labiau pabrėžia namo prestižinį statusą.</p><p><br></p><p>Sovietmečiu pastatas buvo nacionalizuotas: pirmame aukšte veikė valstybinės parduotuvės, o butai pertvarkyti į bendrabučio tipo gyvenamąsias erdves, smarkiai pakeitusias pirminę planinę struktūrą. Nepaisant pokyčių ir šiandien matomo nusidėvėjimo, pastatas išlieka svarbiu Kauno tarpukario architektūros paveldo objektu.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/36.jpg', '54.88973600', '23.92675900');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('37', 'Bendrovės „Butas“ daugiabutis (dabar – privatus)', '1932 m., architektas Jonas Kriščiukaitis', 'Trakų g. 5', '<p>Tarpukario Kaune nauji gyvenamieji namai iškildavo ne tik individualių užsakovų, bet ir bendraminčių ar bendruomenių iniciatyva. Vienas iš tokių pavyzdžių – Trakų gatvėje pastatytas daugiabutis, kurį 1932 m. pasistatė aukščiausio rango Lietuvos vyriausiojo tribunolo pareigūnai, susibūrę į vieną pirmųjų daugiabučių statybos kooperatyvų, pavadintą itin paprastai – „Butas“.</p><p><br></p><p>Tarp jų – rašytojas, teisėtyrininkas, pirmasis Vyriausiojo tribunolo pirmininkas prof. Antanas Kriščiukaitis (Aišbė), inžinieriai Jonas ir Kazys Kriščiukaičiai bei teisininkas, visuomenininkas, Kauno miesto tarybos narys, evangelikų liuteronų kunigas Mykolas Kavolis, sociologo Vytauto Kavolio tėvas. Šiame name gyveno ir pats pastato architektas Jonas Kriščiukaitis.</p><p><br></p><p>Pastatui parinkta rami, tačiau strategiškai patogi vieta – netoli miesto centro, prie Vytauto parko šlaitų, kur tuo metu tik buvo formuojama Trakų gatvė. Lokacija leido suderinti privatų gyvenimą su profesine veikla, išvengiant miesto šurmulio.</p><p><br></p><p>Planuojant erdves atsižvelgta į skirtingus poreikius: pirmajame aukšte suplanuoti du nedideli butai aptarnaujančiam personalui, į kuriuos patenkama tiesiai iš įvažos, o pagrindiniuose aukštuose įrengti erdvūs penkių kambarių butai. Pastarieji išdėstyti pagal aiškų funkcinį zonavimą – atskirtos viešosios, privačiosios ir buitinės erdvės. Prie holų išdėstyti kabinetai ir atskiri tualetai klientūrai, taip netrikdant šeimyninio gyvenimo. Tarp paradinės ir ūkinės laiptinių, pastato centre, buvo įrengtas liftas – tuo metu itin modernus ir retas sprendimas.</p><p><br></p><p>Daugiabučio konstrukcija taip pat novatoriška: inžinierius A. Rozenbliumas pritaikė monolitinį gelžbetonio karkasą, kuris gyvenamųjų namų statyboje tarpukario Lietuvoje buvo tikra retenybė. Dėl šios priežasties namas sulaukė ir visuomenės dėmesio.</p><p><br></p><p>Fasado kompozicija santūri ir aiški, būdinga simetrija, centrinę ašį pabrėžiantis vertikalus laiptinės langas ir ritmiškai išdėstyti platūs langai. Modernų charakterį sustiprino nuo antrojo aukšto kylantys aptakūs erkeriai su išlenktais kampiniais langais ir prie jų esančiais balkonai. Aukšti, siauri laiptinės langai – vadinamieji „termometrai“ – tapo savitu šio ir kitų modernistinių daugiabučių bruožu.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/37.jpg', '54.89623060', '23.92815050');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('38', 'Aleksoto funikulierius', '1935 m., įrangą pagamino ir sumontavo bendrovė „THEODOR BELL und Cie“', 'Amerikos Lietuvių g. 6', '<p>Kaunas išlieka vieninteliu miestu Baltijos šalyse, turinčiu net du tarpukarinius funikulierius, o Aleksoto keltuvas – vienas ryškiausių šio miesto išskirtinumo simbolių. 2025 metais Aleksoto funikulierius minėjo solidų 90 metų jubiliejų. Per dešimtmečius jis neprarado savo populiarumo – ir šiandien tai ne tik turistų pamėgta atrakcija, bet ir patogus, patikimas bei išskirtinis kasdienio susisiekimo būdas, tapęs neatsiejama Kauno miesto tapatybės dalimi. </p><p><br></p><p>Kartu tai vienas įspūdingiausių Optimizmo architektūros objektų. Jis subtiliai pabrėžia Kauno urbanistinį savitumą – kalvotą reljefą ir glaudų miesto bei gamtos ryšį. Funikulierius sujungia Senamiestį su Aleksoto kalnu ir apžvalgos aikštele, nuo kurios atsiveria viena gražiausių miesto panoramų.</p><p><br></p><p>Medinius vagonėlius pagamino Kaune veikusi įmonė „Amlit“, bendradarbiaudama su Šveicarijos inžinieriais. Vos per keliasdešimt sekundžių funikulierius įveikia 133 metrų atkarpą stačiu, net 18° kampu. Nuo pat veikimo pradžios buvo įrengti modernūs saugumo sprendimai – automatiniai stabdžiai, kurie nutrūkus lynui neleidžia vagonams nuriedėti. Vienu metu funikulieriumi gali keliauti iki 25 žmonių, o keliamoji galia siekė 2 tūkst. kilogramų.</p><p><br></p><p>Tarpukario spauda liudijo šios transporto priemonės svarbą kasdieniam miesto gyvenimui: „Aleksoto funikulierius per dieną nuveža tūkstantį keleivių, padaro 200 reisų ir gauna 79,80 litų pajamų“. Pirmaisiais keleiviais tapo to meto ministrai ir burmistrai, o atidarymo iškilmės bei pirmosios kelionės buvo net nufilmuotos.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/38.jpg', '54.89099380', '23.88697310');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('39', 'Buvęs Antano Gylio ligoninės pastatas (dabar – privatus)', '1933 m., architektas Leonas Ritas', 'V. Putvinskio g. 62', '<p>Vienas pastatas – dvi pažangios funkcijos. Taip galima apibūdinti 1933 m. prestižinėje V. Putvinskio gatvėje iškilusį L. Rito projektuotą namą, kuriame įkurta moderni vidaus ir nervų ligų ligoninė, o ketvirtajame aukšte gyveno jos savininkas – gydytojas, filosofijos mokslų daktaras ir aktyvus visuomenininkas Antanas Gylys.</p><p><br></p><p>Užsienyje – Maskvoje ir Miunchene – vidaus ligų ir psichiatrijos studijas baigęs A. Gylys 1924 m. grįžo į Lietuvą ir pradėjo dėstyti Vytauto Didžiojo universiteto Teologijos ir filosofijos fakultete. 1934 m. jis pasitraukė iš akademinės veiklos ir, pasistatęs modernų pastatą, visiškai atsidėjo privačiai medicinos praktikai. Ligoninė netrukus tapo pripažinta kaip viena moderniausių tokio pobūdžio gydymo įstaigų tarpukario Lietuvoje.</p><p><br></p><p>Pastato architektūra pasižymi asketiškomis formomis, funkcionalumu ir santūria estetika. Aiškią tūrinę kompoziciją paįvairina asimetriškas bokštinio tipo rizalitas, o dideli, beveik tolygiai išdėstyti langai užtikrina patalpų šviesumą ir higienos reikalavimus. Pastato mezoninas ir atvira terasa tapo ne tik poilsio erdve, bet ir išskirtine Naujamiesčio panoramos stebėjimo vieta.</p><p><br></p><p>Funkcinė pastato struktūra aiškiai hierarchizuota: pirmajame aukšte veikė hidroterapijos skyrius, antrajame – pacientų priėmimo patalpos, trečiajame – ligoninės stacionaras. Čia buvo įrengti hidroterapijos, helioterapijos ir fizioterapijos skyriai, aprūpinti naujausia to meto medicinine aparatūra, nenusileidusia Vakarų Europos klinikoms. Vidaus planas mišrus, o pagrindinis įėjimas suplanuotas ne iš gatvės, bet iš įvažos – taip buvo užtikrinamas pacientų ir personalo privatumas.</p><p><br></p><p>Nors šiandien pastatas privatus ir nebeatlieka gydymo funkcijų, jame iki šiol išliko daug autentiškų interjero ir techninės įrangos elementų. Vis dar veikia originalus šveicariškas firmos „Schindler“ liftas, išsaugoti hidroterapijos skyriaus santechniniai įrenginiai, firmos „Peltz“ seifas bei išorinės medinės žaliuzės, saugojusios patalpas nuo intensyvios pietinės saulės.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/39.jpg', '54.90089690', '23.91130010');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('40', 'Šančių gimnazija (dabar – KTU Vaižganto progimnazija)', '1938 m., architektas Stasys Kudokas', 'Skuodo g. 27', '<p>Šančių gimnazija – vienas ryškiausių tarpukario Lietuvos modernizmo mokyklų architektūros pavyzdžių, suprojektuotas architekto Stasio Kudoko. Pastatas laikomas antruoju svarbiausiu architekto kūriniu po Karininkų Ramovės rūmų ir puikiai atspindi jo profesinę brandą bei novatorišką požiūrį į visuomeninių pastatų architektūrą.</p><p><br></p><p>Gimnazijos statyba pradėta 1937 m. vasarą,  užbaigta 1938 m. rugsėjį. Statybos kaštai viršijo 1 milijoną litų – ugdymo įstaiga tapo viena didžiausių ir geriausiai įrengtų ketvirtojo dešimtmečio mokyklų Lietuvoje.</p><p><br></p><p>Nors pradžioje vietos parinkimas Aukštuosiuose Šančiuose sukėlė nemažai diskusijų, naujos gimnazijos atidarymas sutiktas su dideliu džiaugsmu. Tarpukariu miesto gimnazijos buvo perpildytos, todėl modernūs ir erdvūs Šančių gimnazijos rūmai tapo svarbiu švietimo infrastruktūros plėtros žingsniu. Skaičiuojama, kad pastate veikė apie 16 klasių, čia mokėsi maždaug 600 gimnazistų.</p><p><br></p><p>Pastato architektūra atspindi mokykloms būdingas laikotarpio tendencijas: funkcionalumą, aiškią struktūrą ir santūrų formų modernumą. Eksterjero kompozicijoje dominuoja aiški langų ir vertikalių elementų ritmika, kurią pabrėžia pirmojo aukšto langus siekiantis tamsaus granitinio tinko cokolis.</p><p><br></p><p>Reprezentacinį pastato charakterį formuoja pagrindinio įėjimo rizalitas su įduboje įleistomis granitinėmis puskolonėmis. Virš durų angų įrengti kronšteinai skirti skulptūroms. Pastato iškilmingumą sustiprina platūs, dvipusiai laiptai. Netikėtą kompozicinį kontrastą sukuria puscilindrio formos laiptinės tūris, suskaidytas kvadratiniais langeliais.</p><p><br></p><p>Pastatas iki pat šių dienų išlaikęs savo funkciją – čia veikia KTU Vaižganto progimnazija. Ją baigė žymūs Lietuvos mokslo, kultūros ir visuomenės veikėjai, tarp jų – Eduardas Mieželaitis, Janina Degutytė, Monika Mironaitė ir kiti.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/40.jpg', '54.87724210', '23.94199500');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('41', '„Pasakos“ kino teatras (dabar – pramogų ir laisvalaikio centras „Nautilus“)', '1939–1940 m., architektai Jokūbas Rabinavičius, Juozas Segalauskas', 'Savanorių pr. 124', '<p>Kauno kino teatras „Pasaka“ – vienas paskutiniųjų kino teatrų, pradėtų statyti tarpukariu ir atidarytų dar nepriklausomoje Lietuvoje. Jo durys žiūrovams atsivėrė 1940 m. kovo 8 d., o pirmuosiuose seansuose buvo rodoma Lietuvos kronika bei amerikiečių „Metro Goldwyn Mayer“ kino filmų nuomos kontoros parengtos apžvalgos. Tai liudija siekį būti moderniu teatru ir atliepti to meto kino kultūros tendencijas.</p><p><br></p><p>Pastatas suprojektuotas siauro ir ilgo tūrio, nutįsusio giliai į sklypą, todėl tokia planinė struktūra lėmė žiūrovams ne itin patogią salės formą. Siekiant pagerinti eksploatacijos sąlygas, dar projektavimo etape ieškota sprendimų, leidžiančių sušvelninti šiuos trūkumus. Salėje įrengtas kelių linkių grindų nuolydis, o žiūrovų vietos suskirstytos į atskirus sektorius su individualiais įėjimais ir išėjimais. Taip pat buvo patvirtintas detaliai apgalvotas vietų išdėstymo planas bei matymo schema.</p><p><br></p><p>Iš viso kino teatre suprojektuotos 487 vietos: 353 parteryje, 21 ložėse, išdėstytose šachmatiniu būdu, ir 113 balkone. Rytinėje pastato pusėje įrengta siaura, koridorių primenanti fojė, o prie gatvės, abipus vestibiulio, veikė krautuvėlės, papildančios pastato funkcionalumą ir suteikiančios jam daugiau gyvybės.</p><p><br></p><p>Plano netobulumus kompensavo išraiškinga architektūra. Fasadas atspindi ketvirtajame dešimtmetyje kino teatrų statyboje paplitusias Art Deco stilistikos kryptis, pasižyminčias dinamika ir veržlumu. Reprezentatyvus, tačiau lakoniškas pagrindinis fasadas formuojamas vertikaliomis iškyšomis, kurios įrėmina centrinę, paaukštintą pastato dalį ir laiptuotais segmentais sujungia ją su šoniniais tūriais. </p><p><br></p><p>Architektūrinį įspūdį stiprino šviečianti kino teatro pavadinimo iškaba „PASAKA“, iliuminuojantys vamzdeliai, laiptuotas terasinis siluetas bei vertikaliai orientuotos briaunos. Įėjimas įtrauktas į atvirą prieangį, kurio profiliuoti kraštai atkartojo laiptų ritmą, o dekoratyvus balkonas atliko ir stogelio funkciją.</p><p><br></p><p>Skirtingai nei panašiu metu duris atvėrusiai „Romuvai“, „Pasakoje“ kino filmai rodyti tik apie dešimtmetį. Sovietmečiu pastate įsikūrė Medicinos instituto Sporto katedra, o buvusi kino salė pritaikyta sporto reikmėms. Septintajame dešimtmetyje statiniui trumpam sugrąžinta pirminė paskirtis – čia vėl pradėjo veikti 420 vietų kino teatras, tačiau jo veikla truko neilgai. Kaip ir daugelis Kauno kino teatrų, „Pasaka“ ilgainiui bankrutavo. Pirmajame XXI amžiaus dešimtmetyje pastatas rekonstruotas, o jo erdvėse veikė naktinis klubas.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/41.jpg', '54.90591780', '23.92206139');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('42', 'Vatikano diplomatinės atstovybės (nunciatūros) pastatas (dabar – Kauno menininkų namai)', '1930 m., architektas Vytautas Landsbergis-Žemkalnis', 'V. Putvinskio g. 56', '<p>Tęsiant kelionę po buvusią Kalnų (V. Putvinskio) gatvę, stabtelėti priverčia 56 numeriu pažymėtas pastatas, kuriame šiandien veikia gyvybingas kultūros centras – Kauno menininkų namai. Miestui tapus šalies sostine, šio pastato istorija išgyveno netikėtą virsmą.</p><p><br></p><p>Pastatas – vienintelis Kaune, kurį Lietuvos Respublikos Užsienio reikalų ministerija specialiai užsakė užsienio diplomatinei atstovybei – Vatikano nunciatūrai. Jį suprojektavo 1930 m. žymus architektas Vytautas Landsbergis-Žemkalnis.</p><p><br></p><p>Vila pastatyta Žaliakalnio šlaite, atokiau nuo gatvės, nors tuo metu galioję statybos reikalavimai numatė ištisinį užstatymą. Šiam reprezentacinės paskirties pastatui buvo padaryta išimtis, todėl jis įgijo vilai būdingą charakterį, primenantį itališko renesanso tradicijas.</p><p><br></p><p>Asimetriško tūrio pastatas pasižymi solidžiomis, tačiau neperkrautomis formomis – tai pabrėžia ryškus karnizas, terasa su laiptais ir aiškios fasadų plokštumos. Vidus suplanuotas itin lanksčiai: pirmajame aukšte numatytos darbo ir priėmimo erdvė – kanceliarija, kabinetai, salonas, valgomasis bei žiemos sodas. Šias patalpas skyrė sustumiamos pertvaros – jas atvėrus, erdvė galėjo virsti didele sale iškilmėms. Antrajame aukšte suplanuoti miegamieji kambariai ir koplyčia.</p><p><br></p><p>Vis dėlto dėl politinių aplinkybių nunciatūra čia taip ir neįsikūrė. Pastatas greitai rado kitą paskirtį – jau 1932 m. jame veikė vaikų ligoninė. Vėliau, sovietmečiu, čia buvo įkurtas tuberkuliozės dispanseris, darželis, kurį laiką veikė ir rinkiminė apylinkė. Nuo 1971 m. pastate įsikūrė miesto Kultūros skyrius, o netrukus gimė visiems gerai žinoma erdvė – Kauno menininkų namai. Šiandien ji laikoma viena ilgiausiai veikiančių tokio tipo kultūros įstaigų Lietuvoje. Čia susitinka istorija, architektūra ir menas.</p>', 'https://modernist.kaunas.lt/ehl-pastatai/42.jpg', '54.90096010', '23.91219000');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('43', 'Architekto Stasio Kudoko namas', '1938 m., architektas Stasys Kudokas', 'V. Mykolaičio-Putino g. 11', '<p>S. Kudokas pasistatė namus, atspindinčius ne to meto architektūrines tendencijas, bet jo paties kūrybinę filosofiją – pastatuose turi derėti racionalumas ir meniškumas.</p><p><br></p><p>Vienintelis lietuvis tarpukariu turėjęs architektūros daktaro laipsnį, įgytą Milane, savo namui pasirinko sudėtingą, tačiau įspūdingą sklypą ant stataus Vytauto kalno šlaito. Dėl reljefo pastato grindys išdėstytos skirtinguose lygiuose, įrengta nemažai mezoninų (pusaukščių). Stačiakampio plano pastatas pasižymi iškyšomis, lodžijomis, galerijomis bei arkadomis, kurios suteikia jam išskirtinį architektūrinį charakterį.</p><p><br></p><p>Namo vidus suplanuotas itin funkcionaliai: keliuose aukštuose išsidėstė šeimos gyvenamosios erdvės, architekto darbo kabinetas, kuriame dirbdavo ir jo praktikantai. Čia vietos atsirado ir trijų kambarių nuomojamam butui. Erdvus holas, miegamasis bei kitos patalpos buvo sujungtos į vientisą, patogią struktūrą. Ant plokščio stogo įrengta terasa, o pietinėje sklypo pusėje – sodas su nedideliu fontanu, atspindinčiu renesanso įtaką.</p><p><br></p><p>S. Kudoko kūryboje ryški Italijos architektūros įtaka – atsispindi ir paties suprojektuotame name. Nors pastatas pasižymi modernistinėmis  – laisvu langų išdėstymu, didelės sienų plokštumomis ir plokščiu stogu – savybėmis, jame gausu ir dekoratyvių elementų: arkinių galerijų, dekoratyvių elementų, skulptūrų. Pagrindinio fasado nišoje įkomponuota Broniaus Pundzio skulptūrėlė „Motinystė“, o bokšto tarpaukštį puošia tulpių bareljefas. Ši funkcionalumo ir dekoratyvumo sintezė neretai vadinama savitu „kudokišku modernizmu“.</p><p><br></p><p>Tarpukariu vila buvo įvertinta ir oficialiai – 1938 m. už estetišką ir patogų mūrinį pastatą ji buvo premijuota Kauno miesto savivaldybės. Prasidėjus antrajai sovietinei okupacijai, 1944 m., S. Kudokas pasitraukė iš Lietuvos ir tęsė savo veiklą Jungtinėse Amerikos Valstijose. Skaičiuojama, kad tarpukario Lietuvoje jo palikimas siekia apie 140 pastatų. </p><p><br></p><p>Sovietmečiu vila buvo padalinta į kelis butus – čia apsigyveno keturios šeimos, o apie 9 dešimtmetyje pastatas buvo pertvarkytas, uždengiant jį šlaitiniu stogu. Šiandien name vis dar yra išlikę autentiški architektūriniai elementai: medinė laiptinė su „teraco“ pakopomis, parketo grindys, lubų apvadai, įmontuotos spintos, arkados ir balkonai. </p>', 'https://modernist.kaunas.lt/ehl-pastatai/43.jpg', '54.89412580', '23.93125010');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('44', 'Ginklavimo Valdybos tyrimų laboratorijos pastatų komplekso Tyrimų laboratorija (dabar – Kauno technologijos universiteto Chemijos technologijų fakultetas)', '1933–1935 m., architektas Vytautas Landsbergis-Žemkalnis', 'Radvilėnų pl. 19', '<p>Teritoriniai ginčai ir besikeičianti šalies bei regiono geopolitinė situacija, vertė valstybę rūpintis saugumu ir nelikti ginklavimosi procesų nuošalyje. Ilgą laiką karinė amunicija tiekta iš užsienio valstybių, tačiau kylančios kainos, finansų stoka ir kiti ekonominiai bei politiniai sumetimai privertė ieškoti alternatyvų.</p><p><br></p><p>Valdžia nusprendė kurti vietinę ginklų pramonę ir taip aprūpinti Ginklavimo Valdybą ir kitas Krašto apsaugos ministerijos įstaigas būtinosiomis priemonėmis. Įsikūrė įvairūs laboratorijos skyriai, pavyzdžiui: organinės chemijos, mikrobiologijos, sprogstamųjų medžiagų, mechanikos, prekių tyrimo. </p><p><br></p><p>Žaliakalnyje Ginklavimosi (Tyrimų) laboratorija atidaryta 1935 m. Šio statinio iniciatorius, vėliau tapęs ir laboratorijos vadovu – inžinierius dr. Juozas Vėbra. Įkvėpimo jis sėmėsi lankydamasis net 8 naujausiose panašios paskirties laboratorijose Vokietijoje, Belgijoje, Prancūzijoje, Šveicarijoje ir Ispanijoje.</p><p><br></p><p>Statinyje derinamas modernizmo pastatams būdingas funkcionalumas ir estetika. Išskirtinę išvaizdą turinčios pastato dalys turi labai praktišką paskirtį: plokšti stogai pritaikyti laboratoriniams bandymams lauke; ištisi juostiniai langai – kad įvykus sprogimui bandymų metu, oro banga „išneštų“ tik langus; dekoratyviniai žali kaminėliai atlieka ortakių paskirtį.</p><p><br></p><p>Objekto architektūroje galima rasti ir „tautinio stiliaus“ elementų. Apie jį ryškiausiai byloja klasikinės simetrijos, kompoziciškai akcentuoti ir ne visuomet funkcionalūs įėjimai. </p><p><br></p><p>Tyrimų laboratorija – brangiausiai kainavęs tarpukario Lietuvos statinys. Jam išleista 2,3 mln. litų. Didžiąją išlaidų dalį sudarė ne statybos priemonės, o prietaisų kaštai. Ji ne veltui laikyta geriausia Baltijos šalyse ir viena geriausių Rytų Europoje. Čia veikė moderniausia aparatūra, leidusi kokybiškai atlikti tiek karinius, tiek kitoms pramonės šakoms reikalingus tyrimus. Didžioji įrangos dalis užsakyta iš Prancūzijos, o mikroskopai, spektografas, fotometrai, precizinė elektros matavimo aparatūra – iš Vokietijos. Emaliuoti Volviko lavos laboratoriniai stalai iš tolimosios Islandijos.</p><p><br></p><p>Istorinės paskirties pastatas iki šių dienų išlaikė savo autentišką išvaizdą, mažai pakitusį interjerą ir pirminę taikomojo mokslo ir tyrimų veiklą. Daugybė studentų vis dar naudojasi išlikusia originalia įranga. </p><p><br></p><p>Architektūrinė vertė taip pat didžiulė. Dar 1973 m. pastatui suteiktas architektūros paminklo statusas. Tyrimų laboratorijos pavadinimas įrašytas ir į saugomų nekilnojamųjų kultūros vertybių bei kultūros paminklų sąrašą. 2019 m. statinys pateko tarp dešimties išskirtinės vertės modernistinės pasaulio architektūros pavyzdžių, kuriam skirta prestižinio „Getty“ fondo parama.</p>', '../../ehl-pastatai/69e87cf03d939.jpg', '54.90562020', '23.95155250');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('45', 'Buvęs verslininko Jono Lapėno namas (dabar – privatus)', '1932 m., architektas Feliksas Vizbaras', 'Kęstučio g. 38', '<p>Didžiausias daugiabutis ir vienas iš Kauno „dangorėžių“ priklausė verslininkui milijonieriui Jonui Lapėnui, bendrovės „Maistas“ direktoriui, Tautininkų partijos lyderiui. Energingas ekonomistas buvo „Lietuvos muilo“ ir „Lietūkio“ valdybų pirmininkas, vienas iš knygų ir periodinės spaudos leidybos bendrovės „Pažanga“ bei „Vilkolakio“ teatro steigėjų.</p><p><br></p><p>Šešiaaukštis nuomojamų butų namas, suprojektuotas garsaus inžinieriaus Felikso Vizbaro, iškilo 1932–1933 m. pagal aukščiausius tarpukario standartus: turėjo centrinį šildymą ir vandenį, kanalizaciją, du liftus. Pastate dera tautinė ornamentika bei modernios stilistikos elementai.</p><p><br></p><p>Statant pastatą, naudotos aukščiausios kokybės apdailos medžiagos, paprastai skirtos viešiesiems pastatams: granitinis tinkas sienoms ir poliruotas rudas granitas tarpduriuose. Pagrindinį fasadą pabrėžia tamsaus tinko juostos, langai su apdaila, metaliniais balkonų turėklais. Tai sukūrė prašmatnumo įspūdį, tapo prabangos etalonu tarpukario Kaune.</p><p><br></p><p>Namo struktūra simetriška, centrinę dalį vainikuoja laiptuotas atikas, o šonuose stovi penkiaaukščiai rizalitai. Ūkinė ir pagrindinė laiptinės viena nuo kitos atskirtos dekoratyvine stiklo sienele. Toks zonavimas atskyrė namo reprezentacinę ir aptarnaujančio personalo funkcijas. Į Kęstučio gatvę atgręžtos prabangių butų patalpos, o kiemo pusėje glaudėsi virtuvės su šaldymo spintomis, tarnaičių kambariai, miegamieji.</p><p><br></p><p>Pirmas aukštas su vitrininiais langais dedikuotas parduotuvėms, likusios erdvės – butai. Iš viso – aštuonios penkių kambarių rezidencijos. Kieme papildomai pastatyti „sandėliai, garažai ir kambariai šoferiams“. Viršutinis, šeštasis aukštas, skirtas bendrosioms gyventojų reikmėms: salė su židiniu, pastogėje – sargo butas. Daugelis originalių baldų išlikę iki šių dienų, įskaitant vestibiulio interjerą.</p><p><br></p><p>Nuo 1938 m. vasaros iki 1939 m. rugsėjo čia įsikūrė Lenkijos pasiuntinybė, įrašydama namą į diplomatinio Kauno istoriją. Sujungus du butus, čia įrengtos devynių kambarių reprezentacinės patalpos. Šiandien tai liudija ant namo kabanti atminimo lenta.</p><p><br></p><p>Išskirtinės architektūros pastatas pateko ir į populiariosios literatūros puslapius – kaip viena pagrindinių veiksmo vietų, jis figūruoja V. Sirijos Giros romane „Raudonmedžio rojus“.</p><p><br></p><p>Ankstyvuoju sovietmečiu, nacionalizavus pastatą, jame įkurdintas Žemės ūkio akademijos bendrabutis, vėliau – mokslinių tyrimų institutas. Šiandien čia įsikūrę biurai, o pastatas vėl tapo prestižine vieta verslui ir bendruomenės veiklai.</p>', '../../ehl-pastatai/69e87d368688d.jpg', '54.89573600', '23.91581230');
INSERT INTO `buildings_en` (`id`, `buildingName`, `buildingAuthor`, `buildingAddress`, `buildingDescription`, `imageSrc`, `latitude`, `longitude`) VALUES ('46', 'Pradžios mokykla (dabar – Jono Jablonskio gimnazija)', '1930–1931 m., architektas Antanas Jokimas', 'Aušros g. 3', '<p>Dabartinis Jono Jablonskio gimnazijos pastatas – vienas ambicingiausių ir moderniausių tarpukario Lietuvos švietimo architektūros projektų, atspindintis valstybės pastangas kurti pažangią, europietišką mokyklų sistemą. Lietuvai atkūrus nepriklausomybę ir 1922 m. įtvirtinus privalomąjį pradinį mokslą, šalyje atsirado didžiulis naujų mokyklų poreikis. Vien Kaune per dešimtmetį pastatytos 36 pradinės mokyklos, o visoje Lietuvoje nuo 1932 m. kasmet iškildavo vidutiniškai apie 80 naujų ugdymo įstaigų.</p><p><br></p><p>Plečiantis miestui ir augant gyventojų skaičiui, Kauno miesto valdyba patikėjo inžinieriui ir architektui Antanui Jokimui suprojektuoti dvi modernias pradines mokyklas – lietuvių vaikams Aušros ir Žemaičių gatvių kampe ir kitą žydų vaikams prie Uosto kranto (dab. Karaliaus Mindaugo pr.).</p><p><br></p><p>Aušros gatvėje iškilęs pastatas pakeitė nuo 1926 m. čia veikusią medinę mokyklą ir tapo moderniausia pradžios mokykla Lietuvoje. Joje įrengtos gimnastikos ir aktų bei kino salės, keturi rankdarbių kabinetai bei pirmasis ir vienintelis baseinas Lietuvoje, išskirtinai dedikuotas mokinių fiziniam ugdymui.</p><p><br></p><p>Duris atvėrusi įstaiga gavo Jono Jablonskio vardą ir greitai pelnė prestižinės mokyklos reputaciją. Čia mokytis veržėsi vaikai iš Žaliakalnio ir kitų Kauno rajonų, todėl klasės buvo perpildytos – kai kuriose mokėsi apie pusšimtį mokinių. Tėvai gyrė aukštą mokymo ir auklėjimo lygį, mokinių laikas čia buvo griežtai reglamentuojamas – kiekvieną pirmadienį aktų salėje vaikai melsdavosi, giedodavo Lietuvos himną ir klausydavosi vedėjo pamokomojo žodžio.</p><p><br></p><p>Pastato architektūroje atsispindi naujausios to meto modernizmo tendencijos: mokyklai būdingi dideli, gausios dienos šviesos įleidžiantys langai, aukštos lubos, aiškus funkcinis zonavimas. Lakoniškus fasadus pagyvina kampinis bokštelis – madinga tarpukario architektūros detalė, taip pat subtilios sienų braukos (grioveliai sienų paviršiuje) ir minimalus dekoras.</p><p><br></p><p>Antrojo pasaulinio karo metais, per vokiečių okupaciją, mokykla tapo karo ligonine. Tik 1946 m. pastatas grąžintas švietimui, o mokykla pervadinta 10-ąja pradine. Vėliau ji reorganizuota į septynmetę ir vidurinę mokyklą, o 1958 m. sugrąžintas J. Jablonskio vardas. Bėgant dešimtmečiams pastatas pasipildė dviem priestatais, mokykla tapo gimnazija, įgijusia humanitarinio ir realinio profilio statusus.</p><p><br></p><p>Per daugiau nei aštuonis dešimtmečius J. Jablonskio gimnazija tapo svarbia Lietuvos kultūros ir visuomenės asmenybių ugdymo vieta. Čia mokėsi prezidentas Valdas Adamkus, poetai, menininkai, politikai, čia dirbo žymūs kultūros veikėjai – pavyzdžiui, kompozitorius ir kariljonininkas Viktoras Kuprevičius.</p>', '../../ehl-pastatai/69e87d8460541.jpg', '54.90300600', '23.91946760');
